INSERT INTO `b_iblock_element` VALUES (1,'2025-09-15 15:51:12',1,'2025-09-15 15:51:11',1,1,NULL,'Y','2010-05-25 00:00:00',NULL,500,'Мебельный форум Беларуси',NULL,'С 20 по 23 апреля 2010 года состоится <strong>Мебельный Форум Беларуси</strong> &ndash; важнейшее мероприятии отрасли в текущем году.','html',NULL,'\r\n<p>С 20 по 23 апреля 2010 года состоится <strong>Мебельный Форум Беларуси</strong> &ndash; важнейшее мероприятии отрасли в текущем году. В экспозиции принимают участие свыше 160 компаний из <em>Беларуси, Австрии, Латвии, Литвы, России, Польши </em>и<em> Украины</em>. В составе форума состоится пять выставок:&quot;Минский мебельный салон&quot;, &quot;Мебельные технологии&quot;, &quot;ОфисКомфорт&quot;, &quot;Кухня&quot; и &quot;Домотех&quot;. Экспозиция будет строиться по принципу двух тематических секторов:<em> готовой мебели</em> и <em>материалов для ее производства</em>.\r\n \r\n \r\n \r\n  <br />\r\n\r\n \r\n \r\n </p>\r\n\r\n \r\n \r\n \r\n \r\n \r\n \r\n<p>В секторе готовой мебели будут представлены:</p>\r\n\r\n \r\n \r\n \r\n \r\n \r\n \r\n<ul>\r\n \r\n \r\n \r\n  <li>корпусная и мягкая мебель;</li>\r\n\r\n \r\n \r\n \r\n \r\n \r\n \r\n  <li>мебель для детей и молодежи;</li>\r\n\r\n \r\n \r\n \r\n \r\n \r\n \r\n  <li>предметы интерьера;</li>\r\n\r\n \r\n \r\n \r\n \r\n \r\n \r\n  <li>кухонная мебель;</li>\r\n\r\n \r\n \r\n \r\n \r\n \r\n \r\n  <li>мебель для офиса и административных зданий.</li>\r\n\r\n \r\n \r\n </ul>\r\n\r\n \r\n \r\n \r\n \r\n \r\n \r\n<p>В секторе материалов для производства мебели будут демонстрироваться новинки рынка мебельной фурнитуры, материалов, обивочных тканей, элементов и аксессуаров для производства мебели.\r\n \r\n \r\n  <br />\r\n\r\n \r\n \r\n </p>\r\n\r\n \r\n \r\n \r\n \r\n<p>Помимо расширенной экспозиции пяти тематических выставок &quot;Экспофорум&quot; подготовил разнообразную деловую программу Мебельного форума. В рамках выставки состоятся семинары и мастер-классы. И поистине масштабным в этом году обещает стать республиканский конкурс форума &quot;<strong>Народное признание</strong>&quot;. В этом году он выходит за рамки выставки и становится республиканским смотром образцов мебели.\r\n \r\n \r\n  <br />\r\n\r\n \r\n <strong>Мебельный Форум</strong> предоставляет специалистам возможность познакомиться с тенденциями мебельной моды, провести переговоры, получить практические предложения рынка, увидеть перспективы развития и новые конкурентные преимущества. Впервые для участников конкурса будет подготовлен маркетинговый отчет по результатам опроса посетителей выставок <strong>Мебельного Форума</strong>.\r\n \r\n \r\n  <br />\r\n\r\n \r\n </p>\r\n\r\n<p><em>Прием заявок на участие в конкурсе осуществляется до 12 апреля 2010 года.</em></p>\r\n\r\n \r\n \r\n \r\n \r\n<ul>\r\n </ul>\r\n\r\n \r\n \r\n \r\n ','html','МЕБЕЛЬНЫЙ ФОРУМ БЕЛАРУСИ\r\nС 20 ПО 23 АПРЕЛЯ 2010 ГОДА СОСТОИТСЯ МЕБЕЛЬНЫЙ \r\nФОРУМ БЕЛАРУСИ &NDASH; ВАЖНЕЙШЕЕ МЕРОПРИЯТИИ ОТРАСЛИ В ТЕКУЩЕМ ГОДУ.\r\nС 20 ПО 23 АПРЕЛЯ 2010 ГОДА СОСТОИТСЯ МЕБЕЛЬНЫЙ \r\nФОРУМ БЕЛАРУСИ &NDASH; ВАЖНЕЙШЕЕ МЕРОПРИЯТИИ ОТРАСЛИ В ТЕКУЩЕМ ГОДУ. В ЭКСПОЗИЦИИ ПРИНИМАЮТ УЧАСТИЕ СВЫШЕ 160 КОМПАНИЙ ИЗ БЕЛАРУСИ, АВСТРИИ, ЛАТВИИ, ЛИТВЫ, РОССИИ, ПОЛЬШИ И УКРАИНЫ. В СОСТАВЕ ФОРУМА СОСТОИТСЯ ПЯТЬ ВЫСТАВОК:\"МИНСКИЙ МЕБЕЛЬНЫЙ САЛОН\", \"МЕБЕЛЬНЫЕ ТЕХНОЛОГИИ\", \"ОФИСКОМФОРТ\", \"КУХНЯ\" И \"ДОМОТЕХ\". ЭКСПОЗИЦИЯ БУДЕТ СТРОИТЬСЯ ПО ПРИНЦИПУ ДВУХ ТЕМАТИЧЕСКИХ СЕКТОРОВ: ГОТОВОЙ МЕБЕЛИ И МАТЕРИАЛОВ ДЛЯ ЕЕ ПРОИЗВОДСТВА. \r\n \r\n\r\nВ СЕКТОРЕ ГОТОВОЙ МЕБЕЛИ БУДУТ ПРЕДСТАВЛЕНЫ: \r\n\r\n- КОРПУСНАЯ И МЯГКАЯ МЕБЕЛЬ; \r\n- МЕБЕЛЬ ДЛЯ ДЕТЕЙ И МОЛОДЕЖИ; \r\n- ПРЕДМЕТЫ ИНТЕРЬЕРА; \r\n- КУХОННАЯ МЕБЕЛЬ; \r\n- МЕБЕЛЬ ДЛЯ ОФИСА И АДМИНИСТРАТИВНЫХ ЗДАНИЙ. \r\n\r\nВ СЕКТОРЕ МАТЕРИАЛОВ ДЛЯ ПРОИЗВОДСТВА \r\nМЕБЕЛИ БУДУТ ДЕМОНСТРИРОВАТЬСЯ НОВИНКИ РЫНКА МЕБЕЛЬНОЙ ФУРНИТУРЫ, МАТЕРИАЛОВ, ОБИВОЧНЫХ ТКАНЕЙ, ЭЛЕМЕНТОВ И АКСЕССУАРОВ ДЛЯ ПРОИЗВОДСТВА МЕБЕЛИ. \r\n \r\n\r\nПОМИМО РАСШИРЕННОЙ ЭКСПОЗИЦИИ ПЯТИ ТЕМАТИЧЕСКИХ \r\nВЫСТАВОК \"ЭКСПОФОРУМ\" ПОДГОТОВИЛ РАЗНООБРАЗНУЮ ДЕЛОВУЮ ПРОГРАММУ МЕБЕЛЬНОГО ФОРУМА. В РАМКАХ ВЫСТАВКИ СОСТОЯТСЯ СЕМИНАРЫ И МАСТЕР-КЛАССЫ. И ПОИСТИНЕ МАСШТАБНЫМ В ЭТОМ ГОДУ ОБЕЩАЕТ СТАТЬ РЕСПУБЛИКАНСКИЙ КОНКУРС ФОРУМА \"НАРОДНОЕ ПРИЗНАНИЕ\". В ЭТОМ ГОДУ ОН ВЫХОДИТ ЗА РАМКИ ВЫСТАВКИ И СТАНОВИТСЯ РЕСПУБЛИКАНСКИМ СМОТРОМ ОБРАЗЦОВ МЕБЕЛИ. \r\nМЕБЕЛЬНЫЙ ФОРУМ ПРЕДОСТАВЛЯЕТ СПЕЦИАЛИСТАМ \r\nВОЗМОЖНОСТЬ ПОЗНАКОМИТЬСЯ С ТЕНДЕНЦИЯМИ МЕБЕЛЬНОЙ МОДЫ, ПРОВЕСТИ ПЕРЕГОВОРЫ, ПОЛУЧИТЬ ПРАКТИЧЕСКИЕ ПРЕДЛОЖЕНИЯ РЫНКА, УВИДЕТЬ ПЕРСПЕКТИВЫ РАЗВИТИЯ И НОВЫЕ КОНКУРЕНТНЫЕ ПРЕИМУЩЕСТВА. ВПЕРВЫЕ ДЛЯ УЧАСТНИКОВ КОНКУРСА БУДЕТ ПОДГОТОВЛЕН МАРКЕТИНГОВЫЙ ОТЧЕТ ПО РЕЗУЛЬТАТАМ ОПРОСА ПОСЕТИТЕЛЕЙ ВЫСТАВОК МЕБЕЛЬНОГО ФОРУМА. \r\n \r\n\r\nПРИЕМ ЗАЯВОК НА УЧАСТИЕ В КОНКУРСЕ ОСУЩЕСТВЛЯЕТСЯ \r\nДО 12 АПРЕЛЯ 2010 ГОДА.',1,NULL,NULL,NULL,NULL,NULL,'N','1','','','-384246935',NULL,6,'2025-09-16 05:11:32'),(2,'2025-09-15 15:51:12',1,'2025-09-15 15:51:12',1,1,NULL,'Y','2010-05-26 00:00:00',NULL,500,'Международная мебельная выставка SALON DEL MOBILE',NULL,'В 2010 году выставка Salon del Mobile обещает быть еще более расширенной и интересной. ','html',NULL,'В 2010 году выставка Salon del Mobile обещает быть еще более расширенной и интересной. На выставке Salon del Mobile будут представлены все типы мебели для офиса и дома от спален и гостиных до VIP-кабинетов, включая оборудование для сада и детской мебели. Заявки на участие подали более чем 1 500 компаний со всего мира. Предполагается, что за время проведения выставки ее посетят более 300 000 тысяч человек. Экспозиция выставки разместится на общей площади 149 871 кв.м. В 2010 году эта поистине грандиозная выставка будет проводиться уже в 10-й раз.','text','МЕЖДУНАРОДНАЯ МЕБЕЛЬНАЯ ВЫСТАВКА SALON DEL MOBILE\r\nВ 2010 ГОДУ ВЫСТАВКА SALON DEL MOBILE ОБЕЩАЕТ БЫТЬ \r\nЕЩЕ БОЛЕЕ РАСШИРЕННОЙ И ИНТЕРЕСНОЙ.\r\nВ 2010 ГОДУ ВЫСТАВКА SALON DEL MOBILE ОБЕЩАЕТ БЫТЬ ЕЩЕ БОЛЕЕ РАСШИРЕННОЙ И ИНТЕРЕСНОЙ. НА ВЫСТАВКЕ SALON DEL MOBILE БУДУТ ПРЕДСТАВЛЕНЫ ВСЕ ТИПЫ МЕБЕЛИ ДЛЯ ОФИСА И ДОМА ОТ СПАЛЕН И ГОСТИНЫХ ДО VIP-КАБИНЕТОВ, ВКЛЮЧАЯ ОБОРУДОВАНИЕ ДЛЯ САДА И ДЕТСКОЙ МЕБЕЛИ. ЗАЯВКИ НА УЧАСТИЕ ПОДАЛИ БОЛЕЕ ЧЕМ 1 500 КОМПАНИЙ СО ВСЕГО МИРА. ПРЕДПОЛАГАЕТСЯ, ЧТО ЗА ВРЕМЯ ПРОВЕДЕНИЯ ВЫСТАВКИ ЕЕ ПОСЕТЯТ БОЛЕЕ 300 000 ТЫСЯЧ ЧЕЛОВЕК. ЭКСПОЗИЦИЯ ВЫСТАВКИ РАЗМЕСТИТСЯ НА ОБЩЕЙ ПЛОЩАДИ 149 871 КВ.М. В 2010 ГОДУ ЭТА ПОИСТИНЕ ГРАНДИОЗНАЯ ВЫСТАВКА БУДЕТ ПРОВОДИТЬСЯ УЖЕ В 10-Й РАЗ.',1,NULL,NULL,NULL,NULL,NULL,'N','8','','','373546319',NULL,7,'2025-09-16 05:11:31'),(3,'2025-09-15 15:51:12',1,'2025-09-15 15:51:12',1,1,NULL,'Y','2010-05-27 00:00:00',NULL,500,'Получено прочное водостойкое соединение',NULL,'Получено новое прочное водостойкое клеевое соединение.Изобретение относится к области получения и применения клеящих составов, используемых в деревообрабатывающей, мебельной и строительной промышленности. Данная клеевая композиция предназначена только для горячего прессования и имеет в своем составе многокомпонентный отвердитель. ','html',NULL,'<b>Авторы изобретения</b>: Разиньков Егор Михайлович  и Мещерякова Анна Анатольевна </br>\r\n              Патент Российской Федерации RU2277566</br>\r\n              <h3>Описание изобретения</h3>\r\n              <p>Изобретение относится к области получения и применения клеящих составов, используемых в деревообрабатывающей, мебельной и строительной промышленности.\r\n              Данная клеевая композиция предназначена только для горячего прессования и имеет в своем составе многокомпонентный отвердитель. Прототипом клеевой композиции является клей, состоящий из карбамидоформальдегидной смолы, сополимера акрилонитрила с N-винилкапролактамом и отвердитель. В качестве отвердителя применяют хлористый аммоний либо акриловую кислоту. </p>\r\n\r\n              <p>Изобретение решает задачу по получению прочного и водостойкого клеевого соединения.\r\n              Это достигается тем, что клеевая композиция, включающая синтетическую смолу и отвердитель, согласно изобретению, дополнительно содержит модификатор, причем в качестве синтетической смолы клеевая композиция включает карбамидомеламиноформальдегидную смолу с отвердителем 2542, в качестве модификатора - карбамидоформальдегидную смолу, а в качестве отвердителя - 10%-ный раствор щавелевой кислоты при следующем соотношении компонентов, мас.ч.:\r\n              </p>\r\n              <table cellspacing=\"10\">\r\n              <tr>\r\n              <td>Карбамидомеламиноформальдегидная смола</td><td>64,5-79,2</td>\r\n              </tr>	\r\n              <tr>\r\n              <td>10%-ный Раствор щавелевой кислоты</td><td>4,4-20,5</td>\r\n\r\n              </tr>\r\n              <tr>\r\n              <td> Отвердитель для карбамидомеламиноформальдегидной </td><td>0,6-2,0</td>\r\n              </tr>\r\n              <tr>\r\n              <td> смолы 2542</td><td>13,0-15,8</td>\r\n\r\n              </tr>	\r\n              </table>\r\n','html','ПОЛУЧЕНО ПРОЧНОЕ ВОДОСТОЙКОЕ СОЕДИНЕНИЕ\r\nПОЛУЧЕНО НОВОЕ ПРОЧНОЕ ВОДОСТОЙКОЕ КЛЕЕВОЕ \r\nСОЕДИНЕНИЕ.ИЗОБРЕТЕНИЕ ОТНОСИТСЯ К ОБЛАСТИ ПОЛУЧЕНИЯ И ПРИМЕНЕНИЯ КЛЕЯЩИХ СОСТАВОВ, ИСПОЛЬЗУЕМЫХ В ДЕРЕВООБРАБАТЫВАЮЩЕЙ, МЕБЕЛЬНОЙ И СТРОИТЕЛЬНОЙ ПРОМЫШЛЕННОСТИ. ДАННАЯ КЛЕЕВАЯ КОМПОЗИЦИЯ ПРЕДНАЗНАЧЕНА ТОЛЬКО ДЛЯ ГОРЯЧЕГО ПРЕССОВАНИЯ И ИМЕЕТ В СВОЕМ СОСТАВЕ МНОГОКОМПОНЕНТНЫЙ ОТВЕРДИТЕЛЬ.\r\nАВТОРЫ ИЗОБРЕТЕНИЯ: РАЗИНЬКОВ ЕГОР МИХАЙЛОВИЧ \r\nИ МЕЩЕРЯКОВА АННА АНАТОЛЬЕВНА ПАТЕНТ РОССИЙСКОЙ ФЕДЕРАЦИИ RU2277566 ОПИСАНИЕ ИЗОБРЕТЕНИЯ \r\n\r\nИЗОБРЕТЕНИЕ ОТНОСИТСЯ К ОБЛАСТИ ПОЛУЧЕНИЯ \r\nИ ПРИМЕНЕНИЯ КЛЕЯЩИХ СОСТАВОВ, ИСПОЛЬЗУЕМЫХ В ДЕРЕВООБРАБАТЫВАЮЩЕЙ, МЕБЕЛЬНОЙ И СТРОИТЕЛЬНОЙ ПРОМЫШЛЕННОСТИ. ДАННАЯ КЛЕЕВАЯ КОМПОЗИЦИЯ ПРЕДНАЗНАЧЕНА ТОЛЬКО ДЛЯ ГОРЯЧЕГО ПРЕССОВАНИЯ И ИМЕЕТ В СВОЕМ СОСТАВЕ МНОГОКОМПОНЕНТНЫЙ ОТВЕРДИТЕЛЬ. ПРОТОТИПОМ КЛЕЕВОЙ КОМПОЗИЦИИ ЯВЛЯЕТСЯ КЛЕЙ, СОСТОЯЩИЙ ИЗ КАРБАМИДОФОРМАЛЬДЕГИДНОЙ СМОЛЫ, СОПОЛИМЕРА АКРИЛОНИТРИЛА С N-ВИНИЛКАПРОЛАКТАМОМ И ОТВЕРДИТЕЛЬ. В КАЧЕСТВЕ ОТВЕРДИТЕЛЯ ПРИМЕНЯЮТ ХЛОРИСТЫЙ АММОНИЙ ЛИБО АКРИЛОВУЮ КИСЛОТУ. \r\n\r\nИЗОБРЕТЕНИЕ РЕШАЕТ ЗАДАЧУ ПО ПОЛУЧЕНИЮ \r\nПРОЧНОГО И ВОДОСТОЙКОГО КЛЕЕВОГО СОЕДИНЕНИЯ. ЭТО ДОСТИГАЕТСЯ ТЕМ, ЧТО КЛЕЕВАЯ КОМПОЗИЦИЯ, ВКЛЮЧАЮЩАЯ СИНТЕТИЧЕСКУЮ СМОЛУ И ОТВЕРДИТЕЛЬ, СОГЛАСНО ИЗОБРЕТЕНИЮ, ДОПОЛНИТЕЛЬНО СОДЕРЖИТ МОДИФИКАТОР, ПРИЧЕМ В КАЧЕСТВЕ СИНТЕТИЧЕСКОЙ СМОЛЫ КЛЕЕВАЯ КОМПОЗИЦИЯ ВКЛЮЧАЕТ КАРБАМИДОМЕЛАМИНОФОРМАЛЬДЕГИДНУЮ СМОЛУ С ОТВЕРДИТЕЛЕМ 2542, В КАЧЕСТВЕ МОДИФИКАТОРА - КАРБАМИДОФОРМАЛЬДЕГИДНУЮ СМОЛУ, А В КАЧЕСТВЕ ОТВЕРДИТЕЛЯ - 10%-НЫЙ РАСТВОР ЩАВЕЛЕВОЙ КИСЛОТЫ ПРИ СЛЕДУЮЩЕМ СООТНОШЕНИИ КОМПОНЕНТОВ, МАС.Ч.: \r\n КАРБАМИДОМЕЛАМИНОФОРМАЛЬДЕГИДНАЯ СМОЛА \r\n   64,5-79,2     \r\n 10%-НЫЙ РАСТВОР ЩАВЕЛЕВОЙ КИСЛОТЫ    4,4-20,5 \r\n    \r\n ОТВЕРДИТЕЛЬ ДЛЯ КАРБАМИДОМЕЛАМИНОФОРМАЛЬДЕГИДНОЙ \r\n    0,6-2,0     \r\n СМОЛЫ 2542    13,0-15,8',1,NULL,NULL,NULL,NULL,NULL,'N','9','','','868533081',NULL,7,'2025-09-16 05:11:32'),(30,'2025-09-15 15:51:16',1,'2025-09-15 15:51:16',1,4,NULL,'Y','2010-05-01 00:00:00',NULL,200,'Продавец-дизайнер (кухни)',NULL,'','html',NULL,'<b>Требования</b> 						 						 \r\n<p>Уверенный пользователь ПК, навыки черчения от руки и в программах, опыт работы дизайнером/конструктором в мебельной сфере, этика делового общения</p>\r\n 						 						<b>Обязанности</b> 						 \r\n<p>Консультирование клиентов по кухонной мебели, оставление художественно-конструкторских проектов, прием и оформление заказов.</p>\r\n 						 						<b>Условия</b> 						 \r\n<p>Зарплата: 13500 оклад + % от личных продаж + премии‚ совокупный доход от 20000 руб,полный соц. пакет‚ оформление согласно ТК РФ</p>\r\n ','html','ПРОДАВЕЦ-ДИЗАЙНЕР (КУХНИ)\r\n\r\nТРЕБОВАНИЯ \r\n\r\nУВЕРЕННЫЙ ПОЛЬЗОВАТЕЛЬ ПК, НАВЫКИ ЧЕРЧЕНИЯ \r\nОТ РУКИ И В ПРОГРАММАХ, ОПЫТ РАБОТЫ ДИЗАЙНЕРОМ/КОНСТРУКТОРОМ В МЕБЕЛЬНОЙ СФЕРЕ, ЭТИКА ДЕЛОВОГО ОБЩЕНИЯ ОБЯЗАННОСТИ \r\n\r\nКОНСУЛЬТИРОВАНИЕ КЛИЕНТОВ ПО КУХОННОЙ \r\nМЕБЕЛИ, ОСТАВЛЕНИЕ ХУДОЖЕСТВЕННО-КОНСТРУКТОРСКИХ ПРОЕКТОВ, ПРИЕМ И ОФОРМЛЕНИЕ ЗАКАЗОВ. УСЛОВИЯ \r\n\r\nЗАРПЛАТА: 13500 ОКЛАД + % ОТ ЛИЧНЫХ ПРОДАЖ + \r\nПРЕМИИ‚ СОВОКУПНЫЙ ДОХОД ОТ 20000 РУБ,ПОЛНЫЙ СОЦ. ПАКЕТ‚ ОФОРМЛЕНИЕ СОГЛАСНО ТК РФ',1,NULL,NULL,NULL,NULL,NULL,'N','2','','','1704140047',NULL,NULL,NULL),(31,'2025-09-15 15:51:16',1,'2025-09-15 15:51:16',1,4,NULL,'Y','2010-05-01 00:00:00',NULL,300,'Директор магазина',NULL,'','html',NULL,'<b>Требования</b> 						 						 \r\n<p>Высшее образование‚ опыт руководящей работы в рознице от 3 лет‚ опытный пользователь ПК‚ этика делового общения‚ знание методов управления и заключения договоров‚ отличное знание торгового и трудового законодательств‚ ответственность‚ инициативность‚ активность.</p>\r\n 						 						<b>Обязанности</b> 						 \r\n<p>Руководство деятельностью магазина‚ организация эффективной работы персонала магазина‚ финансово-хозяйственная деятельность и отчетность‚ выполнение плана продаж‚ отчетность.</p>\r\n 						 						<b>Условия</b> 						 \r\n<p>Трудоустройство по ТК РФ‚ полный соц. пакет‚ график работы 5 чере 2 (168 час/мес)‚ зарплата: оклад 28000 + % от оборота + премии‚ совокупный доход от 35000 руб</p>\r\n ','html','ДИРЕКТОР МАГАЗИНА\r\n\r\nТРЕБОВАНИЯ \r\n\r\nВЫСШЕЕ ОБРАЗОВАНИЕ‚ ОПЫТ РУКОВОДЯЩЕЙ \r\nРАБОТЫ В РОЗНИЦЕ ОТ 3 ЛЕТ‚ ОПЫТНЫЙ ПОЛЬЗОВАТЕЛЬ ПК‚ ЭТИКА ДЕЛОВОГО ОБЩЕНИЯ‚ ЗНАНИЕ МЕТОДОВ УПРАВЛЕНИЯ И ЗАКЛЮЧЕНИЯ ДОГОВОРОВ‚ ОТЛИЧНОЕ ЗНАНИЕ ТОРГОВОГО И ТРУДОВОГО ЗАКОНОДАТЕЛЬСТВ‚ ОТВЕТСТВЕННОСТЬ‚ ИНИЦИАТИВНОСТЬ‚ АКТИВНОСТЬ. ОБЯЗАННОСТИ \r\n\r\nРУКОВОДСТВО ДЕЯТЕЛЬНОСТЬЮ МАГАЗИНА‚ ОРГАНИЗАЦИЯ \r\nЭФФЕКТИВНОЙ РАБОТЫ ПЕРСОНАЛА МАГАЗИНА‚ ФИНАНСОВО-ХОЗЯЙСТВЕННАЯ ДЕЯТЕЛЬНОСТЬ И ОТЧЕТНОСТЬ‚ ВЫПОЛНЕНИЕ ПЛАНА ПРОДАЖ‚ ОТЧЕТНОСТЬ. УСЛОВИЯ \r\n\r\nТРУДОУСТРОЙСТВО ПО ТК РФ‚ ПОЛНЫЙ СОЦ. ПАКЕТ‚ \r\nГРАФИК РАБОТЫ 5 ЧЕРЕ 2 (168 ЧАС/МЕС)‚ ЗАРПЛАТА: ОКЛАД 28000 + % ОТ ОБОРОТА + ПРЕМИИ‚ СОВОКУПНЫЙ ДОХОД ОТ 35000 РУБ',1,NULL,NULL,NULL,NULL,NULL,'N','3','','','192768702',NULL,NULL,NULL),(32,'2025-09-15 15:51:16',1,'2025-09-15 15:51:16',1,4,NULL,'Y','2010-05-01 00:00:00',NULL,400,'Бухгалтер отдела учета готовой продукции',NULL,'','html',NULL,'<b>Требования</b> 						 						 \r\n<p>Жен., 22-45, уверенный пользователь ПК, опыт работы бухгалтером приветсвуется, знание бухгалтерского учета (базовый уровень), самостоятельность, ответственность, коммуникабельность, быстрая обучаемость, желание работать.</p>\r\n 						 						<b>Обязанности</b> 						 \r\n<p>Работа с первичными документами по учету МПЗ Ведение журналов-ордеров по производственным счетам Формирование материальных отчетов подразделений Исполнение дополнительных функций по указанию руководителя</p>\r\n 						 						<b>Условия</b> 						 \r\n<p>График работы 5 дней в неделю, адрес работы г. Шатура, Ботинский пр-д, 37. Зарплата: оклад 10 800 р. + премия 40% от оклада, полный соц. пакет.</p>\r\n ','html','БУХГАЛТЕР ОТДЕЛА УЧЕТА ГОТОВОЙ ПРОДУКЦИИ\r\n\r\nТРЕБОВАНИЯ \r\n\r\nЖЕН., 22-45, УВЕРЕННЫЙ ПОЛЬЗОВАТЕЛЬ ПК, ОПЫТ \r\nРАБОТЫ БУХГАЛТЕРОМ ПРИВЕТСВУЕТСЯ, ЗНАНИЕ БУХГАЛТЕРСКОГО УЧЕТА (БАЗОВЫЙ УРОВЕНЬ), САМОСТОЯТЕЛЬНОСТЬ, ОТВЕТСТВЕННОСТЬ, КОММУНИКАБЕЛЬНОСТЬ, БЫСТРАЯ ОБУЧАЕМОСТЬ, ЖЕЛАНИЕ РАБОТАТЬ. ОБЯЗАННОСТИ \r\n\r\nРАБОТА С ПЕРВИЧНЫМИ ДОКУМЕНТАМИ ПО УЧЕТУ \r\nМПЗ ВЕДЕНИЕ ЖУРНАЛОВ-ОРДЕРОВ ПО ПРОИЗВОДСТВЕННЫМ СЧЕТАМ ФОРМИРОВАНИЕ МАТЕРИАЛЬНЫХ ОТЧЕТОВ ПОДРАЗДЕЛЕНИЙ ИСПОЛНЕНИЕ ДОПОЛНИТЕЛЬНЫХ ФУНКЦИЙ ПО УКАЗАНИЮ РУКОВОДИТЕЛЯ УСЛОВИЯ \r\n\r\nГРАФИК РАБОТЫ 5 ДНЕЙ В НЕДЕЛЮ, АДРЕС РАБОТЫ \r\nГ. ШАТУРА, БОТИНСКИЙ ПР-Д, 37. ЗАРПЛАТА: ОКЛАД 10 800 Р. + ПРЕМИЯ 40% ОТ ОКЛАДА, ПОЛНЫЙ СОЦ. ПАКЕТ.',1,NULL,NULL,NULL,NULL,NULL,'N','4','','','790068583',NULL,NULL,NULL),(41,'2026-01-19 13:34:34',1,'2026-01-19 13:34:34',1,9,15,'Y',NULL,NULL,500,'Тест Масло гидравлическое ВИПРО',NULL,'Тест Масло гидравлическое ВИПРО','text',NULL,'Масло предназначено для систем гидроусилителя руля, гидрообъемных передач и гидравлических систем автомобильной техники, в том числе техники специального назначения. ','text','ТЕСТ МАСЛО ГИДРАВЛИЧЕСКОЕ ВИПРО\r\nТЕСТ МАСЛО ГИДРАВЛИЧЕСКОЕ ВИПРО\r\nМАСЛО ПРЕДНАЗНАЧЕНО ДЛЯ СИСТЕМ ГИДРОУСИЛИТЕЛЯ РУЛЯ, ГИДРООБЪЕМНЫХ ПЕРЕДАЧ И ГИДРАВЛИЧЕСКИХ СИСТЕМ АВТОМОБИЛЬНОЙ ТЕХНИКИ, В ТОМ ЧИСЛЕ ТЕХНИКИ СПЕЦИАЛЬНОГО НАЗНАЧЕНИЯ. ',1,NULL,NULL,NULL,NULL,NULL,'Y','56c3f2a5-a359-11f0-9593-f61e6c17d77a',NULL,NULL,'1473970168',NULL,NULL,NULL),(42,'2026-01-28 10:19:05',1,'2026-01-27 16:41:08',1,10,16,'Y',NULL,NULL,500,'Кинематическая вязкость при 100°C по ГОСТ 33',NULL,'Кинематическая вязкость при 100°C по ГОСТ 33','text',73,'Компания Симэкс-Хим располагает аттестованной лабораторией анализа смазочных материалов, которая оснащена современным оборудованием. Специалисты компании, обладая накопленным научным опытом и знаниями в разработке, проверке и производстве смазочных материалов, обеспечивают постоянный контроль качества сырьевых компонентов и продукции, адаптацию продуктов к специфическим требованиям заказчиков, реализующих свои проекты в разных странах, географических поясах и погодных условиях.\nНаша испытательная лаборатория анализа смазочных материалов предлагает услуги по проведению анализа определения термоокислительной стабильности и коррозионной активности смазочных материалов. Данный анализ проводится согласно ГОСТ 20944-75.\n\nМетодика проведения анализа на определение термоокислительной стабильности и коррозионной активности по ГОСТ 20944-75\n\nСущность метода заключается в окислении жидкости в контакте с металлами и воздухом, с нагревом до 200°C. Термоокислительную стабильность жидкости оценивают по изменению внешнего ви','text','КИНЕМАТИЧЕСКАЯ ВЯЗКОСТЬ ПРИ 100°C ПО ГОСТ 33\r\nКИНЕМАТИЧЕСКАЯ ВЯЗКОСТЬ ПРИ 100°C ПО ГОСТ 33\r\nКОМПАНИЯ СИМЭКС-ХИМ РАСПОЛАГАЕТ АТТЕСТОВАННОЙ ЛАБОРАТОРИЕЙ АНАЛИЗА СМАЗОЧНЫХ МАТЕРИАЛОВ, КОТОРАЯ ОСНАЩЕНА СОВРЕМЕННЫМ ОБОРУДОВАНИЕМ. СПЕЦИАЛИСТЫ КОМПАНИИ, ОБЛАДАЯ НАКОПЛЕННЫМ НАУЧНЫМ ОПЫТОМ И ЗНАНИЯМИ В РАЗРАБОТКЕ, ПРОВЕРКЕ И ПРОИЗВОДСТВЕ СМАЗОЧНЫХ МАТЕРИАЛОВ, ОБЕСПЕЧИВАЮТ ПОСТОЯННЫЙ КОНТРОЛЬ КАЧЕСТВА СЫРЬЕВЫХ КОМПОНЕНТОВ И ПРОДУКЦИИ, АДАПТАЦИЮ ПРОДУКТОВ К СПЕЦИФИЧЕСКИМ ТРЕБОВАНИЯМ ЗАКАЗЧИКОВ, РЕАЛИЗУЮЩИХ СВОИ ПРОЕКТЫ В РАЗНЫХ СТРАНАХ, ГЕОГРАФИЧЕСКИХ ПОЯСАХ И ПОГОДНЫХ УСЛОВИЯХ.\nНАША ИСПЫТАТЕЛЬНАЯ ЛАБОРАТОРИЯ АНАЛИЗА СМАЗОЧНЫХ МАТЕРИАЛОВ ПРЕДЛАГАЕТ УСЛУГИ ПО ПРОВЕДЕНИЮ АНАЛИЗА ОПРЕДЕЛЕНИЯ ТЕРМООКИСЛИТЕЛЬНОЙ СТАБИЛЬНОСТИ И КОРРОЗИОННОЙ АКТИВНОСТИ СМАЗОЧНЫХ МАТЕРИАЛОВ. ДАННЫЙ АНАЛИЗ ПРОВОДИТСЯ СОГЛАСНО ГОСТ 20944-75.\n\nМЕТОДИКА ПРОВЕДЕНИЯ АНАЛИЗА НА ОПРЕДЕЛЕНИЕ ТЕРМООКИСЛИТЕЛЬНОЙ СТАБИЛЬНОСТИ И КОРРОЗИОННОЙ АКТИВНОСТИ ПО ГОСТ 20944-75\n\nСУЩНОСТЬ МЕТОДА ЗАКЛЮЧАЕТСЯ В ОКИСЛЕНИИ ЖИДКОСТИ В КОНТАКТЕ С МЕТАЛЛАМИ И ВОЗДУХОМ, С НАГРЕВОМ ДО 200°C. ТЕРМООКИСЛИТЕЛЬНУЮ СТАБИЛЬНОСТЬ ЖИДКОСТИ ОЦЕНИВАЮТ ПО ИЗМЕНЕНИЮ ВНЕШНЕГО ВИ',1,NULL,NULL,NULL,NULL,NULL,'Y','4bd38f92-f6b7-11f0-959c-fb299729d190',NULL,NULL,'1139482390',NULL,1,'2026-01-28 11:00:51'),(43,'2026-01-28 10:19:05',1,'2026-01-27 16:41:08',1,10,16,'Y',NULL,NULL,500,'Кинематическая вязкость при 40°C по ГОСТ 33',NULL,'Кинематическая вязкость при 40°C по ГОСТ 33','text',77,'Компания Симэкс-Хим располагает аттестованной лабораторией анализа смазочных материалов, которая оснащена современным оборудованием. Специалисты компании, обладая накопленным научным опытом и знаниями в разработке, проверке и производстве смазочных материалов, обеспечивают постоянный контроль качества сырьевых компонентов и продукции, адаптацию продуктов к специфическим требованиям заказчиков, реализующих свои проекты в разных странах, географических поясах и погодных условиях.\nНаша испытательная лаборатория анализа смазочных материалов предлагает услуги по проведению анализа определения термоокислительной стабильности и коррозионной активности смазочных материалов. Данный анализ проводится согласно ГОСТ 20944-75.\n\nМетодика проведения анализа на определение термоокислительной стабильности и коррозионной активности по ГОСТ 20944-75\n\nСущность метода заключается в окислении жидкости в контакте с металлами и воздухом, с нагревом до 200°C. Термоокислительную стабильность жидкости оценивают по изменению внешнего ви','text','КИНЕМАТИЧЕСКАЯ ВЯЗКОСТЬ ПРИ 40°C ПО ГОСТ 33\r\nКИНЕМАТИЧЕСКАЯ ВЯЗКОСТЬ ПРИ 40°C ПО ГОСТ 33\r\nКОМПАНИЯ СИМЭКС-ХИМ РАСПОЛАГАЕТ АТТЕСТОВАННОЙ ЛАБОРАТОРИЕЙ АНАЛИЗА СМАЗОЧНЫХ МАТЕРИАЛОВ, КОТОРАЯ ОСНАЩЕНА СОВРЕМЕННЫМ ОБОРУДОВАНИЕМ. СПЕЦИАЛИСТЫ КОМПАНИИ, ОБЛАДАЯ НАКОПЛЕННЫМ НАУЧНЫМ ОПЫТОМ И ЗНАНИЯМИ В РАЗРАБОТКЕ, ПРОВЕРКЕ И ПРОИЗВОДСТВЕ СМАЗОЧНЫХ МАТЕРИАЛОВ, ОБЕСПЕЧИВАЮТ ПОСТОЯННЫЙ КОНТРОЛЬ КАЧЕСТВА СЫРЬЕВЫХ КОМПОНЕНТОВ И ПРОДУКЦИИ, АДАПТАЦИЮ ПРОДУКТОВ К СПЕЦИФИЧЕСКИМ ТРЕБОВАНИЯМ ЗАКАЗЧИКОВ, РЕАЛИЗУЮЩИХ СВОИ ПРОЕКТЫ В РАЗНЫХ СТРАНАХ, ГЕОГРАФИЧЕСКИХ ПОЯСАХ И ПОГОДНЫХ УСЛОВИЯХ.\nНАША ИСПЫТАТЕЛЬНАЯ ЛАБОРАТОРИЯ АНАЛИЗА СМАЗОЧНЫХ МАТЕРИАЛОВ ПРЕДЛАГАЕТ УСЛУГИ ПО ПРОВЕДЕНИЮ АНАЛИЗА ОПРЕДЕЛЕНИЯ ТЕРМООКИСЛИТЕЛЬНОЙ СТАБИЛЬНОСТИ И КОРРОЗИОННОЙ АКТИВНОСТИ СМАЗОЧНЫХ МАТЕРИАЛОВ. ДАННЫЙ АНАЛИЗ ПРОВОДИТСЯ СОГЛАСНО ГОСТ 20944-75.\n\nМЕТОДИКА ПРОВЕДЕНИЯ АНАЛИЗА НА ОПРЕДЕЛЕНИЕ ТЕРМООКИСЛИТЕЛЬНОЙ СТАБИЛЬНОСТИ И КОРРОЗИОННОЙ АКТИВНОСТИ ПО ГОСТ 20944-75\n\nСУЩНОСТЬ МЕТОДА ЗАКЛЮЧАЕТСЯ В ОКИСЛЕНИИ ЖИДКОСТИ В КОНТАКТЕ С МЕТАЛЛАМИ И ВОЗДУХОМ, С НАГРЕВОМ ДО 200°C. ТЕРМООКИСЛИТЕЛЬНУЮ СТАБИЛЬНОСТЬ ЖИДКОСТИ ОЦЕНИВАЮТ ПО ИЗМЕНЕНИЮ ВНЕШНЕГО ВИ',1,NULL,NULL,NULL,NULL,NULL,'Y','42f824e5-f6b8-11f0-959c-fb299729d190',NULL,NULL,'-2108230343',NULL,2,'2026-01-28 11:01:00'),(44,'2026-01-27 16:41:38',1,'2026-01-27 16:41:37',1,11,18,'Y',NULL,NULL,500,'Тест Масло гидравлическое SIMY HVLP-32 Бочка 170кг',NULL,'Масло гидравлическое SIMY HVLP-32 Бочка 170кг','text',81,'Высокоэффективное гидравлическое масло, разработанное для наиболее полного соответствия специфическим требованиям эксплуатации в российских условиях современных гидравлических систем, применяющихся в промышленном оборудовании и мобильной технике.\nОтвечает требованиям EATON VICKERS, BOSCH REXROTH и немецкому стандарту DIN51524-3. \nХорошие показатели гидролитической стабильности и водоотталкивающие свойства способствуют превосходной фильтруемости при попадании воды. Антипенные присадки обеспечивают низкий уровень пенообразования, быстрый отвод воздуха, бесперебойную и эффективную работу техники.\nБлагодаря улучшенным вязкостно-температурным харктеристикам, масло сохраняет превосходную текучесть и прокачиваемость при отрицательных температурах, что позволяет обеспечить легкий пуск гидропривода.','text','ТЕСТ МАСЛО ГИДРАВЛИЧЕСКОЕ SIMY HVLP-32 БОЧКА 170КГ\r\nМАСЛО ГИДРАВЛИЧЕСКОЕ SIMY HVLP-32 БОЧКА 170КГ\r\nВЫСОКОЭФФЕКТИВНОЕ ГИДРАВЛИЧЕСКОЕ МАСЛО, РАЗРАБОТАННОЕ ДЛЯ НАИБОЛЕЕ ПОЛНОГО СООТВЕТСТВИЯ СПЕЦИФИЧЕСКИМ ТРЕБОВАНИЯМ ЭКСПЛУАТАЦИИ В РОССИЙСКИХ УСЛОВИЯХ СОВРЕМЕННЫХ ГИДРАВЛИЧЕСКИХ СИСТЕМ, ПРИМЕНЯЮЩИХСЯ В ПРОМЫШЛЕННОМ ОБОРУДОВАНИИ И МОБИЛЬНОЙ ТЕХНИКЕ.\nОТВЕЧАЕТ ТРЕБОВАНИЯМ EATON VICKERS, BOSCH REXROTH И НЕМЕЦКОМУ СТАНДАРТУ DIN51524-3. \nХОРОШИЕ ПОКАЗАТЕЛИ ГИДРОЛИТИЧЕСКОЙ СТАБИЛЬНОСТИ И ВОДООТТАЛКИВАЮЩИЕ СВОЙСТВА СПОСОБСТВУЮТ ПРЕВОСХОДНОЙ ФИЛЬТРУЕМОСТИ ПРИ ПОПАДАНИИ ВОДЫ. АНТИПЕННЫЕ ПРИСАДКИ ОБЕСПЕЧИВАЮТ НИЗКИЙ УРОВЕНЬ ПЕНООБРАЗОВАНИЯ, БЫСТРЫЙ ОТВОД ВОЗДУХА, БЕСПЕРЕБОЙНУЮ И ЭФФЕКТИВНУЮ РАБОТУ ТЕХНИКИ.\nБЛАГОДАРЯ УЛУЧШЕННЫМ ВЯЗКОСТНО-ТЕМПЕРАТУРНЫМ ХАРКТЕРИСТИКАМ, МАСЛО СОХРАНЯЕТ ПРЕВОСХОДНУЮ ТЕКУЧЕСТЬ И ПРОКАЧИВАЕМОСТЬ ПРИ ОТРИЦАТЕЛЬНЫХ ТЕМПЕРАТУРАХ, ЧТО ПОЗВОЛЯЕТ ОБЕСПЕЧИТЬ ЛЕГКИЙ ПУСК ГИДРОПРИВОДА.',1,NULL,NULL,NULL,NULL,NULL,'Y','f300d912-fb4d-11f0-959d-9962a2f85f27',NULL,NULL,'-311643758',NULL,1,'2026-01-28 10:38:46'),(45,'2026-01-28 10:20:10',1,'2026-01-28 10:20:10',1,11,18,'Y',NULL,NULL,500,'Тест Масло гидравлическое ВИПРО',NULL,'Тест Масло гидравлическое ВИПРО','text',82,'Масло разработано в научном центре СИМЭКС-ХИМ по техническому заданию российских производителей автомобильной техники как аналог гидравлических жидкостей сегмента CHF/PSF премиального качества от ведущих мировых производителей смазочных материалов. Технологией изготовления масла ВИПРО предусмотрено применение уникальных присадок и специально подобранных синтетических базовых масел — полиальфаолефинов (ПАО), обеспечивающих оптимальную работу и защиту гидравлических систем. Гидравлическое синтетическое масло ВИПРО производится в строгом соответствии с:\r\n\r\nМасло ВИПРО создано для любых, в том числе экстремальных, условий эксплуатации и имеет следующие преимущества:\r\nмасло первой заливки на конвейере;\r\nподходит для легковых и грузовых автомобилей таких марок как: КАМАЗ, ГАЗ, МАЗ, Урал, MAN, Mercedes, Volvo, Scania;\r\nполностью синтетическое;\r\nработоспособно от минус 50°C до 140°C;\r\nтемпература застывания ниже минус 60°C;\r\nиндекс вязкости 315;\r\nотличная прокачиваемость в системе, даже при низких температурах;\r\nмасло не оказы','text','ТЕСТ МАСЛО ГИДРАВЛИЧЕСКОЕ ВИПРО\r\nТЕСТ МАСЛО ГИДРАВЛИЧЕСКОЕ ВИПРО\r\nМАСЛО РАЗРАБОТАНО В НАУЧНОМ ЦЕНТРЕ СИМЭКС-ХИМ ПО ТЕХНИЧЕСКОМУ ЗАДАНИЮ РОССИЙСКИХ ПРОИЗВОДИТЕЛЕЙ АВТОМОБИЛЬНОЙ ТЕХНИКИ КАК АНАЛОГ ГИДРАВЛИЧЕСКИХ ЖИДКОСТЕЙ СЕГМЕНТА CHF/PSF ПРЕМИАЛЬНОГО КАЧЕСТВА ОТ ВЕДУЩИХ МИРОВЫХ ПРОИЗВОДИТЕЛЕЙ СМАЗОЧНЫХ МАТЕРИАЛОВ. ТЕХНОЛОГИЕЙ ИЗГОТОВЛЕНИЯ МАСЛА ВИПРО ПРЕДУСМОТРЕНО ПРИМЕНЕНИЕ УНИКАЛЬНЫХ ПРИСАДОК И СПЕЦИАЛЬНО ПОДОБРАННЫХ СИНТЕТИЧЕСКИХ БАЗОВЫХ МАСЕЛ — ПОЛИАЛЬФАОЛЕФИНОВ (ПАО), ОБЕСПЕЧИВАЮЩИХ ОПТИМАЛЬНУЮ РАБОТУ И ЗАЩИТУ ГИДРАВЛИЧЕСКИХ СИСТЕМ. ГИДРАВЛИЧЕСКОЕ СИНТЕТИЧЕСКОЕ МАСЛО ВИПРО ПРОИЗВОДИТСЯ В СТРОГОМ СООТВЕТСТВИИ С:\r\n\r\nМАСЛО ВИПРО СОЗДАНО ДЛЯ ЛЮБЫХ, В ТОМ ЧИСЛЕ ЭКСТРЕМАЛЬНЫХ, УСЛОВИЙ ЭКСПЛУАТАЦИИ И ИМЕЕТ СЛЕДУЮЩИЕ ПРЕИМУЩЕСТВА:\r\nМАСЛО ПЕРВОЙ ЗАЛИВКИ НА КОНВЕЙЕРЕ;\r\nПОДХОДИТ ДЛЯ ЛЕГКОВЫХ И ГРУЗОВЫХ АВТОМОБИЛЕЙ ТАКИХ МАРОК КАК: КАМАЗ, ГАЗ, МАЗ, УРАЛ, MAN, MERCEDES, VOLVO, SCANIA;\r\nПОЛНОСТЬЮ СИНТЕТИЧЕСКОЕ;\r\nРАБОТОСПОСОБНО ОТ МИНУС 50°C ДО 140°C;\r\nТЕМПЕРАТУРА ЗАСТЫВАНИЯ НИЖЕ МИНУС 60°C;\r\nИНДЕКС ВЯЗКОСТИ 315;\r\nОТЛИЧНАЯ ПРОКАЧИВАЕМОСТЬ В СИСТЕМЕ, ДАЖЕ ПРИ НИЗКИХ ТЕМПЕРАТУРАХ;\r\nМАСЛО НЕ ОКАЗЫ',1,NULL,NULL,NULL,NULL,NULL,'Y','56c3f2a5-a359-11f0-9593-f61e6c17d77a',NULL,NULL,'-1594475409',NULL,10,'2026-01-28 10:38:34'),(46,'2026-01-28 10:20:18',1,'2026-01-28 10:20:18',1,12,20,'Y',NULL,NULL,500,'Тест Масло гидравлическое SIMY HVLP-32 Бочка 170кг',NULL,'Масло гидравлическое SIMY HVLP-32 Бочка 170кг','text',88,'Высокоэффективное гидравлическое масло, разработанное для наиболее полного соответствия специфическим требованиям эксплуатации в российских условиях современных гидравлических систем, применяющихся в промышленном оборудовании и мобильной технике.\nОтвечает требованиям EATON VICKERS, BOSCH REXROTH и немецкому стандарту DIN51524-3. \nХорошие показатели гидролитической стабильности и водоотталкивающие свойства способствуют превосходной фильтруемости при попадании воды. Антипенные присадки обеспечивают низкий уровень пенообразования, быстрый отвод воздуха, бесперебойную и эффективную работу техники.\nБлагодаря улучшенным вязкостно-температурным харктеристикам, масло сохраняет превосходную текучесть и прокачиваемость при отрицательных температурах, что позволяет обеспечить легкий пуск гидропривода.','text','ТЕСТ МАСЛО ГИДРАВЛИЧЕСКОЕ SIMY HVLP-32 БОЧКА 170КГ\r\nМАСЛО ГИДРАВЛИЧЕСКОЕ SIMY HVLP-32 БОЧКА 170КГ\r\nВЫСОКОЭФФЕКТИВНОЕ ГИДРАВЛИЧЕСКОЕ МАСЛО, РАЗРАБОТАННОЕ ДЛЯ НАИБОЛЕЕ ПОЛНОГО СООТВЕТСТВИЯ СПЕЦИФИЧЕСКИМ ТРЕБОВАНИЯМ ЭКСПЛУАТАЦИИ В РОССИЙСКИХ УСЛОВИЯХ СОВРЕМЕННЫХ ГИДРАВЛИЧЕСКИХ СИСТЕМ, ПРИМЕНЯЮЩИХСЯ В ПРОМЫШЛЕННОМ ОБОРУДОВАНИИ И МОБИЛЬНОЙ ТЕХНИКЕ.\nОТВЕЧАЕТ ТРЕБОВАНИЯМ EATON VICKERS, BOSCH REXROTH И НЕМЕЦКОМУ СТАНДАРТУ DIN51524-3. \nХОРОШИЕ ПОКАЗАТЕЛИ ГИДРОЛИТИЧЕСКОЙ СТАБИЛЬНОСТИ И ВОДООТТАЛКИВАЮЩИЕ СВОЙСТВА СПОСОБСТВУЮТ ПРЕВОСХОДНОЙ ФИЛЬТРУЕМОСТИ ПРИ ПОПАДАНИИ ВОДЫ. АНТИПЕННЫЕ ПРИСАДКИ ОБЕСПЕЧИВАЮТ НИЗКИЙ УРОВЕНЬ ПЕНООБРАЗОВАНИЯ, БЫСТРЫЙ ОТВОД ВОЗДУХА, БЕСПЕРЕБОЙНУЮ И ЭФФЕКТИВНУЮ РАБОТУ ТЕХНИКИ.\nБЛАГОДАРЯ УЛУЧШЕННЫМ ВЯЗКОСТНО-ТЕМПЕРАТУРНЫМ ХАРКТЕРИСТИКАМ, МАСЛО СОХРАНЯЕТ ПРЕВОСХОДНУЮ ТЕКУЧЕСТЬ И ПРОКАЧИВАЕМОСТЬ ПРИ ОТРИЦАТЕЛЬНЫХ ТЕМПЕРАТУРАХ, ЧТО ПОЗВОЛЯЕТ ОБЕСПЕЧИТЬ ЛЕГКИЙ ПУСК ГИДРОПРИВОДА.',1,NULL,NULL,NULL,NULL,NULL,'Y','f300d912-fb4d-11f0-959d-9962a2f85f27',NULL,NULL,'-311643758',NULL,3,'2026-01-28 11:02:07'),(47,'2026-01-28 10:20:24',1,'2026-01-28 10:20:24',1,13,22,'Y',NULL,NULL,500,'Тест Масло гидравлическое SI-HYDRO ВМГЗ-45',NULL,'Масло гидравлическое SI-HYDRO ВМГЗ-45','text',89,'Применяется в качестве всесезонной рабочей жидкости для систем гидропривода строительных, дорожных, лесозаготовительных, подъемно-транспортных, сельскохозяйственных и других машин, работающих на открытом воздухе при температурах в рабочем объеме масла от минус 30 до плюс 80℃ в зависимости от типа гидронасоса.','text','ТЕСТ МАСЛО ГИДРАВЛИЧЕСКОЕ SI-HYDRO ВМГЗ-45\r\nМАСЛО ГИДРАВЛИЧЕСКОЕ SI-HYDRO ВМГЗ-45\r\nПРИМЕНЯЕТСЯ В КАЧЕСТВЕ ВСЕСЕЗОННОЙ РАБОЧЕЙ ЖИДКОСТИ ДЛЯ СИСТЕМ ГИДРОПРИВОДА СТРОИТЕЛЬНЫХ, ДОРОЖНЫХ, ЛЕСОЗАГОТОВИТЕЛЬНЫХ, ПОДЪЕМНО-ТРАНСПОРТНЫХ, СЕЛЬСКОХОЗЯЙСТВЕННЫХ И ДРУГИХ МАШИН, РАБОТАЮЩИХ НА ОТКРЫТОМ ВОЗДУХЕ ПРИ ТЕМПЕРАТУРАХ В РАБОЧЕМ ОБЪЕМЕ МАСЛА ОТ МИНУС 30 ДО ПЛЮС 80℃ В ЗАВИСИМОСТИ ОТ ТИПА ГИДРОНАСОСА.',1,NULL,NULL,NULL,NULL,NULL,'Y','99f55350-fb4e-11f0-959d-9962a2f85f27',NULL,NULL,'1586727339',NULL,1,'2026-04-14 10:26:53'),(48,'2026-05-15 08:53:08',1,'2026-03-20 12:16:55',1,14,24,'Y',NULL,NULL,500,'Тест Масло гидравлическое SI-HYDRO ВМГЗ-45 Канистра 17КГ',NULL,'Масло гидравлическое SI-HYDRO ВМГЗ-45 Канистра 17КГ','text',90,'Применяется в качестве всесезонной рабочей жидкости для систем гидропривода строительных, дорожных, лесозаготовительных, подъемно-транспортных, сельскохозяйственных и других машин, работающих на открытом воздухе при температурах в рабочем объеме масла от минус 30 до плюс 80℃ в зависимости от типа гидронасоса.','text','ТЕСТ МАСЛО ГИДРАВЛИЧЕСКОЕ SI-HYDRO ВМГЗ-45 КАНИСТРА 17КГ\r\nМАСЛО ГИДРАВЛИЧЕСКОЕ SI-HYDRO ВМГЗ-45 КАНИСТРА 17КГ\r\nПРИМЕНЯЕТСЯ В КАЧЕСТВЕ ВСЕСЕЗОННОЙ РАБОЧЕЙ ЖИДКОСТИ ДЛЯ СИСТЕМ ГИДРОПРИВОДА СТРОИТЕЛЬНЫХ, ДОРОЖНЫХ, ЛЕСОЗАГОТОВИТЕЛЬНЫХ, ПОДЪЕМНО-ТРАНСПОРТНЫХ, СЕЛЬСКОХОЗЯЙСТВЕННЫХ И ДРУГИХ МАШИН, РАБОТАЮЩИХ НА ОТКРЫТОМ ВОЗДУХЕ ПРИ ТЕМПЕРАТУРАХ В РАБОЧЕМ ОБЪЕМЕ МАСЛА ОТ МИНУС 30 ДО ПЛЮС 80℃ В ЗАВИСИМОСТИ ОТ ТИПА ГИДРОНАСОСА.',1,NULL,NULL,NULL,NULL,NULL,'Y','563b76e1-1c65-11f1-95a0-d74e013af7ac','','','0',NULL,2,'2026-03-20 12:47:31'),(49,'2026-05-15 08:52:59',1,'2026-03-20 12:16:55',1,14,24,'Y',NULL,NULL,500,'Тест Масло гидравлическое SIMY HVLP-32 Канистра 17КГ',NULL,'Масло гидравлическое SIMY HVLP-32 Канистра 17КГ','text',91,'Высокоэффективное гидравлическое масло, разработанное для наиболее полного соответствия специфическим требованиям эксплуатации в российских условиях современных гидравлических систем, применяющихся в промышленном оборудовании и мобильной технике.\r\nОтвечает требованиям EATON VICKERS, BOSCH REXROTH и немецкому стандарту DIN51524-3. \r\nХорошие показатели гидролитической стабильности и водоотталкивающие свойства способствуют превосходной фильтруемости при попадании воды. Антипенные присадки обеспечивают низкий уровень пенообразования, быстрый отвод воздуха, бесперебойную и эффективную работу техники.\r\nБлагодаря улучшенным вязкостно-температурным харктеристикам, масло сохраняет превосходную текучесть и прокачиваемость при отрицательных температурах, что позволяет обеспечить легкий пуск гидропривода.','text','ТЕСТ МАСЛО ГИДРАВЛИЧЕСКОЕ SIMY HVLP-32 КАНИСТРА 17КГ\r\nМАСЛО ГИДРАВЛИЧЕСКОЕ SIMY HVLP-32 КАНИСТРА 17КГ\r\nВЫСОКОЭФФЕКТИВНОЕ ГИДРАВЛИЧЕСКОЕ МАСЛО, РАЗРАБОТАННОЕ ДЛЯ НАИБОЛЕЕ ПОЛНОГО СООТВЕТСТВИЯ СПЕЦИФИЧЕСКИМ ТРЕБОВАНИЯМ ЭКСПЛУАТАЦИИ В РОССИЙСКИХ УСЛОВИЯХ СОВРЕМЕННЫХ ГИДРАВЛИЧЕСКИХ СИСТЕМ, ПРИМЕНЯЮЩИХСЯ В ПРОМЫШЛЕННОМ ОБОРУДОВАНИИ И МОБИЛЬНОЙ ТЕХНИКЕ.\r\nОТВЕЧАЕТ ТРЕБОВАНИЯМ EATON VICKERS, BOSCH REXROTH И НЕМЕЦКОМУ СТАНДАРТУ DIN51524-3. \r\nХОРОШИЕ ПОКАЗАТЕЛИ ГИДРОЛИТИЧЕСКОЙ СТАБИЛЬНОСТИ И ВОДООТТАЛКИВАЮЩИЕ СВОЙСТВА СПОСОБСТВУЮТ ПРЕВОСХОДНОЙ ФИЛЬТРУЕМОСТИ ПРИ ПОПАДАНИИ ВОДЫ. АНТИПЕННЫЕ ПРИСАДКИ ОБЕСПЕЧИВАЮТ НИЗКИЙ УРОВЕНЬ ПЕНООБРАЗОВАНИЯ, БЫСТРЫЙ ОТВОД ВОЗДУХА, БЕСПЕРЕБОЙНУЮ И ЭФФЕКТИВНУЮ РАБОТУ ТЕХНИКИ.\r\nБЛАГОДАРЯ УЛУЧШЕННЫМ ВЯЗКОСТНО-ТЕМПЕРАТУРНЫМ ХАРКТЕРИСТИКАМ, МАСЛО СОХРАНЯЕТ ПРЕВОСХОДНУЮ ТЕКУЧЕСТЬ И ПРОКАЧИВАЕМОСТЬ ПРИ ОТРИЦАТЕЛЬНЫХ ТЕМПЕРАТУРАХ, ЧТО ПОЗВОЛЯЕТ ОБЕСПЕЧИТЬ ЛЕГКИЙ ПУСК ГИДРОПРИВОДА.',1,NULL,NULL,NULL,NULL,NULL,'Y','c7872c21-1c64-11f1-95a0-d74e013af7ac','','','0',NULL,3,'2026-03-20 12:47:02'),(50,'2026-05-15 08:52:49',1,'2026-03-20 12:16:55',1,14,24,'Y',NULL,NULL,500,'Тест Масло гидравлическое SI-HYDRO ВМГЗ-45 Бочка 170КГ',NULL,'Масло гидравлическое SI-HYDRO ВМГЗ-45 Бочка 170КГ','text',93,'Применяется в качестве всесезонной рабочей жидкости для систем гидропривода строительных, дорожных, лесозаготовительных, подъемно-транспортных, сельскохозяйственных и других машин, работающих на открытом воздух