INSERT INTO `b_search_content` VALUES (1,'2025-09-15 15:43:36','main','s1|/index.html',0,NULL,NULL,NULL,'/index.html','WebHOST1 - сайт припаркован','Ура! Почти готово 🥳\rДомен \rуспешно припаркован &#10004;\rЛичный кабинет\r/ \rБаза знаний\r/ \rКонтакты\rРаботает на базе платформы \rWebhost1\r— надежный NVME SSD-хостинг.','','','','5eb604309160e8fdcf0a9fd9c5db502f',NULL,NULL),(2,'2025-09-15 15:51:10','main','s1|/company/history.php',0,NULL,NULL,NULL,'/company/history.php','История','1992г. 								\r&laquo;Мебельная компания&raquo;\rначиналась с изготовления мебели для школ и офисов. Первое 									производство мебели располагалось в арендуемой мастерской, площадью 400 м2 с одним 									деревообрабатывающим станком. В компании работало двадцать человек. Все заработанные 									средства вкладывались в развитие, что позволило молодой Компании расти быстрыми 									темпами. 								\r1993г. 								\rВведен в эксплуатацию новый цех площадью 700 м2, ставший первой собственностью 									\r&laquo;Мебельной компании&raquo;\r. Модернизация производственной базы предприятия стала хорошей 									традицией. Компания постепенно перешла к более совершенному оборудованию, что позволило 									повысить уровень качества выпускаемой продукции и значительно увеличить объемы производства. 								\r1998г. 								\rВ Воронеже открыт первый фирменный магазин-салон \r&laquo;Мебельная компания&raquo;\r. Шаг за шагом 									продукция предприятия завоевывала регионы Сибири и Урала, Москвы и Подмосковья, 									Юга и Северо-Запада России. Производственные площади компании увеличены до 5000 									м2. 								\r1999г. 								\r&laquo;Мебельная компания&raquo;\rстала дипломантом одной из самых престижных международных 									выставок \r&laquo;ЕвроЭкспоМебель-99&raquo;\r- первое официальное признание мебельной продукции 									&laquo;Мебельной компании&raquo;. В этом же году компания выходит на мировой рынок. Был заключен 									ряд контрактов на поставку мебели в страны СНГ и Ближнего Зарубежья. 								\r2000г. 								\rКоллектив компании насчитывает более 500 сотрудников. Заключаются новые контракт 									на поставку мебели в европейские страны. 								\r2002г. 								\r&laquo;Мебельная компания&raquo;\rвошла в десятку лучших производителей мебели по данным ведущих 									мебельных салонов России, а также в число лидеров организационного развития. 								\r2003г. 								\rПриступили к строительству склада материалов. В Москве открыт филиал компании. \nПроведена первая конференция партнеров, результатом которой стало укрепление взаимовыгодных 									отношений и заключение дилерских договоров. 								\r2004г. 								\rЗавершено строительство и оснащение нового производственного корпуса и склада материалов. \nРасширено представительство компании на российском рынке и за рубежом. \nОткрыто 									региональное представительство \r&laquo;Мебельной компании&raquo;\rв Екатеринбурге. 								\r2005г. 								\rКомпания приобретает новое производственное оборудование концерна - угловую линию 									раскроя материалов и линию загрузки выгрузки. \nНачинается выпуск продукции в 									натуральном шпоне. Формируется отдельный склад материалов и комплектующих. \nВ этом же году открывается Фабрика мягкой мебели \r&laquo;МебельПлюс&raquo;\r2006г. 								\rОткрыты региональные представительства \r&laquo;Мебельной компании&raquo;\rв Санкт-Петербурге 									и Нижнем Новгороде. \nРазвивается собственная розничная сеть фирменных магазинов-салонов 									на территории России. 								\r2007г. 								\rЗавершено строительство второй фабрики. Общая площадь производсвенно-складских корпусов 									Компании составляет уже более 30000 м2. \nПроведена вторая конференция партнеров 									компании \r\"Технология успешного бизнеса\"\r. 								\r2008г. 								\rОткрыто новое предприятие для производства мебели по индивидуальным проектам \r&laquo;Комфорт&raquo;\r. \n&laquo;Мебельная компания&raquo;\rпродолжает обновление оборудования. 								\r2008г. 								\rНовейшим оборудованием укомплектована вторая фабрика. Запущена вторая производственная 									линия. \nПроведена третья конференция \r&laquo;Партнерство - бизнес сегодня&raquo;\rПринято решение о строительстве третьей фабрики. Площадь производственно &mdash; складских 									корпусов составит более 70000м2. \nПо всей стране и зарубежом открыто 37 мебельных 									салонов. \nВ Компании работает более полутора тысяч сотрудников.','','','','5eb604309160e8fdcf0a9fd9c5db502f',NULL,NULL),(3,'2025-09-15 15:51:10','main','s1|/company/index.php',0,NULL,NULL,NULL,'/company/index.php','О компании','Наша компания существует на Российском рынке с 1992 года. За это время \r&laquo;Мебельная компания&raquo;\rпрошла большой путь от маленькой торговой фирмы до одного из крупнейших производителей корпусной мебели в России. 						 \rГлавное правило - индивидуальный подход к каждому клиенту\rНа сегодняшний день нами разработано более пятисот моделей для офиса и дома. Вместе с тем мы стремимся обеспечить неповторимость своей продукции. Мы изготовим мебель для кухни, детской, гостиной, спальной или ванной комнаты, мебель для офиса особого дизайна и нестандартного размера. \rНаши дизайнеры произведут замеры помещения и вместе с вами разработают дизайн-проект мебели для вашего интерьера, подобрав с высокой точностью размеры, модели, цвета, помогут оптимально расположить мебель. \rВаш проект будет создан с учетом всех нюансов и прорисовкой мельчайших деталей. Результаты совместного творчества вы сможете посмотреть в объемном представлении. Вам наглядно продемонстрируют, как будут выглядеть в жизни выбранные элементы интерьера при разном освещении, в конкретном помещении, сделанные из определенных материалов. В ваше распоряжение будет предоставлено много различных вариантов, из которых Вы сможете выбрать наиболее подходящий именно Вам. 						 					\rЗаказ будет выполнен и доставлен точно в срок. Все работы по сборке и установке мебели осуществляют сотрудники нашей компании. Строгий контроль качества осуществляется на всех этапах работ: от момента оформления заказа до момента приема выполненных работ. \rПередовые технологии и бесценный опыт\rИспользование передовых компьютерных технологий, многолетний опыт наших специалистов позволяют произвести грамотные расчеты и снизить расход материалов и себестоимость продукции, избежать ошибок при проектировании и оптимизировать дизайн комплексных интерьеров. Гарантия на нашу продукцию составляет 18 месяцев, а на отдельную продукцию 36 месяцев. \rМы гордимся нашими сотрудниками прошедшими профессиональное обучение в лучших учебных заведениях России и зарубежья. У нас трудятся высококлассные специалисты разных возрастов. Мы ценим энтузиазм молодежи и бесценный опыт старшего поколения. Все мы разные, но нас объединяет преданность своему делу и вера в идеи нашей компании. \rВысочайшие стандарты качества - залог нашего успеха\r&laquo;Мебельная компания&raquo;\rосуществляет производство мебели на высококлассном оборудовании с применением минимальной доли ручного труда, что позволяет обеспечить высокое качество нашей продукции. Налажен производственный процесс как массового и индивидуального характера, что с одной стороны позволяет обеспечить постоянную номенклатуру изделий и индивидуальный подход &ndash; с другой. \rЕжегодно наша продукция проходит сертификационные испытания в специализированных лабораториях России и имеет сертификаты соответствия продукции нормам безопасности и качества. Кроме того, \r&laquo;Мебельная компания&raquo;\rодной из первых среди мебельных производителей России в 2003 году прошла аудит на соответствие требованиям системы менеджмента качества &laquo;ИСО 9000&raquo; и получила сертификат соответствия системы качества на предприятии нормам международного стандарта.','','','','5eb604309160e8fdcf0a9fd9c5db502f',NULL,NULL),(4,'2025-09-15 15:51:10','main','s1|/company/management.php',0,NULL,NULL,NULL,'/company/management.php','Руководство','Успешное развитие бизнеса &ndash; во многом результат квалифицированной работы руководства. 							\r&laquo;Мебельная компания&raquo;\rна мебельном рынке уже 18 лет. За это время Компания 							не только сохранила, но и упрочила лидирующие позиции среди ведущих игроков мебельного 							рынка. 						\r&laquo;Мебельная компания&raquo;\rиз года в год расширяет ассортимент выпускаемой продукции, 							наращивает темпы и объемы производства, увеличивает производственные и складские 							площади, развивает отношения с партнерами со всех регионов страны и налаживает связи 							с зарубежными партнерами. В большой степени это заслуга хорошо подготовленного руководящего 							состава и его грамотной политики. 						\rСобственник Компании &laquo;Мебельная компания&raquo;\rКолесников Виктор Федорович 								\rРодился 3 сентября 1964 года.\nОбразование: закончил авиационный факультет Воронежского 									государственного политехнического института. В 1994 году прошел обучение по программе 									&laquo;Подготовка малого и среднего бизнеса&raquo; в США.\nВ настоящее время Виктор Федорович 									возглавляет Управляющую компанию, которая координирует деятельность предприятий, 									входящих в Группу Компаний \r&laquo;Мебельная компания&raquo;\r. 								\rГенеральный директор &laquo;Мебельной компании&raquo;\rРатченко Александр Петрович 								\rРодился 5 июня 1962 года.\nОбразование: Воронежский политехнический институт 									по специальности инженер-технолог; программа &laquo;Эффективное развитие производства&raquo; 									(США).\nВ \r&laquo;Мебельной компании&raquo;\rСергей Фомич с 1994 года. За это время прошел 									путь от начальника цеха до генерального директора предприятия. 								\rЗаместитель генерального директора Управляющей компании\rРоговой Андрей Владимирович 								\rОбразование: факультет радиотехники Воронежского государственного технического университета.\nВ Компании с 1 июня 2000 года.','','','','5eb604309160e8fdcf0a9fd9c5db502f',NULL,NULL),(5,'2025-09-15 15:51:10','main','s1|/company/mission.php',0,NULL,NULL,NULL,'/company/mission.php','Миссия и стратегия','&laquo;Мебельная компания&raquo;\r- динамично развивающееся производственное 							предприятие, которое имеет перед собой \nясно выраженные цели и инструменты для 							их достижени.Мы предоставляем каждому лучшую возможность обустроить свое жизненное \nи рабочее пространство.Мы работаем на долгосрочную перспективу и предлагаем оптимальные 							решения. Компания \r&laquo;Мебельная компания&raquo;\r- \nнадежный, технологичный, гибкий поставщик 							с большими мощностями. 						\rЦели и задачи\rОправдывать ожидания заказчика: &ldquo;Клиент всегда прав&rdquo;. Только Потребитель формирует 									единую систему взглядов на качество \nвыпускаемой продукции и работ.\rДобиться от работников компании понимания их личной ответственности за качество 									работ.\rПутем повышения качества продукции и работ постоянно увеличивать объемы производства 									с целью последующего реинвестирования \nприбыли в развитие компании.\rОбеспечивать строгое соответствие производимой продукции требованиям потребителей, 									нормам и правилам \nбезопасности, требованиям защиты окружающей среды.\rПолитика компании\rПостоянное совершенствование системы качества. Своевременное и эффективное принятие 									корректирующих мер .\rЗабота о работниках компании. Создание условий труда и оснащение рабочих мест, соответствующих 									всем санитарным \nи гигиеническим нормам.\rПовышение благосостояния сотрудников. Обеспечение морального и материального удовлетворения 									работников компании.\rСистематическое обучение работников всех уровней с целью постоянного повышения их 									профессионального мастерства.\rВнедрение высокопроизводительного оборудования и новейших технологий для повышения 									производительности труда, \nоптимизации затрат и, как результат, снижения цен 									на выпускаемую продукцию.\rСоздание новых рабочих мест. Привлечение на работу специалистов высокой квалификации.\rВыход на международный рынок.\rМы развиваем доверительные взаимовыгодные отношения со своими партнерами в долгосрочных 							интересах нашего бизнеса. \n&laquo;Мебельная компания&raquo;\rответственно относится 							к выполнению взятых на себя обязательств и ждет такого же \nподхода к делу от 							своих партнеров по бизнесу. Эта требовательность &ndash; залог нашей долгосрочной прибыльности. 						\rСо дня своего основания \r&laquo;Мебельная компания&raquo;\rсодействует росту благосостояния 							регионов России. Мы понимаем важность \nсоциальной ответственности нашей Компании 							и останемся примером в вопросах социальной защищенности наших сотрудников.','','','','5eb604309160e8fdcf0a9fd9c5db502f',NULL,NULL),(6,'2025-09-15 15:51:10','main','s1|/company/vacancies.php',0,NULL,NULL,NULL,'/company/vacancies.php','Вакансии','','','','','5eb604309160e8fdcf0a9fd9c5db502f',NULL,NULL),(7,'2025-09-15 15:51:10','main','s1|/contacts/index.php',0,NULL,NULL,NULL,'/contacts/index.php','Контакты','Обратитесь к нашим специалистам и получите профессиональную консультацию по вопросам создания и покупки мебели (от дизайна, разработки технического задания до доставки мебели к Вам домой).\rВы можете обратиться к нам по телефону, по электронной почте или договориться о встрече в нашем офисе. Будем рады помочь вам и ответить на все ваши вопросы. \rТелефоны\rТелефон/факс:\n(495) 212-85-06\rТелефоны:\n(495) 212-85-07\r(495) 212-85-08\rEmail\rinfo@example.ru\r&mdash; общие вопросы\rsales@example.ru\r&mdash; приобретение продукции\rmarketing@example.ru\r&mdash; маркетинг/мероприятия/PR\rОфис в Москве','','','','5eb604309160e8fdcf0a9fd9c5db502f',NULL,NULL),(8,'2025-09-15 15:51:10','main','s1|/login/index.php',0,NULL,NULL,NULL,'/login/index.php','Вход на сайт','Вы зарегистрированы и успешно авторизовались.\rВернуться на главную страницу','','','','5eb604309160e8fdcf0a9fd9c5db502f',NULL,NULL),(9,'2025-09-15 15:51:10','main','s1|/news/index.php',0,NULL,NULL,NULL,'/news/index.php','Новости','','','','','5eb604309160e8fdcf0a9fd9c5db502f',NULL,NULL),(11,'2025-09-15 15:51:10','main','s1|/search/index.php',0,NULL,NULL,NULL,'/search/index.php','Поиск','','','','','5eb604309160e8fdcf0a9fd9c5db502f',NULL,NULL),(12,'2025-09-15 15:51:10','main','s1|/search/map.php',0,NULL,NULL,NULL,'/search/map.php','Карта сайта','','','','','5eb604309160e8fdcf0a9fd9c5db502f',NULL,NULL),(14,'2025-09-15 15:51:10','main','s1|/_index.php',0,NULL,NULL,NULL,'/_index.php','Мебельная компания','Наша компания существует на Российском рынке с 1992 года. За это время «Мебельная компания» прошла большой путь от маленькой торговой фирмы до одного из крупнейших производителей корпусной мебели в России.\n«Мебельная компания» осуществляет производство мебели на высококлассном оборудовании с применением минимальной доли ручного труда, что позволяет обеспечить высокое качество нашей продукции. Налажен производственный процесс как массового и индивидуального характера, что с одной стороны позволяет обеспечить постоянную номенклатуру изделий и индивидуальный подход – с другой.\nНаша продукция\rНаши услуги','','','','5eb604309160e8fdcf0a9fd9c5db502f',NULL,NULL),(15,'2010-05-25 00:00:00','iblock','1',0,NULL,NULL,NULL,'=ID=1&EXTERNAL_ID=1&IBLOCK_SECTION_ID=&IBLOCK_TYPE_ID=news&IBLOCK_ID=1&IBLOCK_CODE=furniture_news&IBLOCK_EXTERNAL_ID=furniture_news&CODE=','Мебельный форум Беларуси','С 20 по 23 апреля 2010 года состоится \rМебельный Форум Беларуси\r&ndash; важнейшее мероприятии отрасли в текущем году.\r\n\rС 20 по 23 апреля 2010 года состоится \rМебельный Форум Беларуси\r&ndash; важнейшее мероприятии отрасли в текущем году. В экспозиции принимают участие свыше 160 компаний из \rБеларуси, Австрии, Латвии, Литвы, России, Польши \rи\rУкраины\r. В составе форума состоится пять выставок:\"Минский мебельный салон\", \"Мебельные технологии\", \"ОфисКомфорт\", \"Кухня\" и \"Домотех\". Экспозиция будет строиться по принципу двух тематических секторов:\rготовой мебели\rи \rматериалов для ее производства\r.\rВ секторе готовой мебели будут представлены:\rкорпусная и мягкая мебель;\rмебель для детей и молодежи;\rпредметы интерьера;\rкухонная мебель;\rмебель для офиса и административных зданий.\rВ секторе материалов для производства мебели будут демонстрироваться новинки рынка мебельной фурнитуры, материалов, обивочных тканей, элементов и аксессуаров для производства мебели.\rПомимо расширенной экспозиции пяти тематических выставок \"Экспофорум\" подготовил разнообразную деловую программу Мебельного форума. В рамках выставки состоятся семинары и мастер-классы. И поистине масштабным в этом году обещает стать республиканский конкурс форума \"\rНародное признание\r\". В этом году он выходит за рамки выставки и становится республиканским смотром образцов мебели.\rМебельный Форум\rпредоставляет специалистам возможность познакомиться с тенденциями мебельной моды, провести переговоры, получить практические предложения рынка, увидеть перспективы развития и новые конкурентные преимущества. Впервые для участников конкурса будет подготовлен маркетинговый отчет по результатам опроса посетителей выставок \rМебельного Форума\r.\rПрием заявок на участие в конкурсе осуществляется до 12 апреля 2010 года.','','news','1',NULL,'2010-05-25 00:00:00',NULL),(16,'2010-05-26 00:00:00','iblock','2',0,NULL,NULL,NULL,'=ID=2&EXTERNAL_ID=8&IBLOCK_SECTION_ID=&IBLOCK_TYPE_ID=news&IBLOCK_ID=1&IBLOCK_CODE=furniture_news&IBLOCK_EXTERNAL_ID=furniture_news&CODE=','Международная мебельная выставка SALON DEL MOBILE','В 2010 году выставка Salon del Mobile обещает быть еще более расширенной и интересной. \r\nВ 2010 году выставка Salon del Mobile обещает быть еще более расширенной и интересной. На выставке Salon del Mobile будут представлены все типы мебели для офиса и дома от спален и гостиных до VIP-кабинетов, включая оборудование для сада и детской мебели. Заявки на участие подали более чем 1 500 компаний со всего мира. Предполагается, что за время проведения выставки ее посетят более 300 000 тысяч человек. Экспозиция выставки разместится на общей площади 149 871 кв.м. В 2010 году эта поистине грандиозная выставка будет проводиться уже в 10-й раз.','','news','1',NULL,'2010-05-26 00:00:00',NULL),(17,'2010-05-27 00:00:00','iblock','3',0,NULL,NULL,NULL,'=ID=3&EXTERNAL_ID=9&IBLOCK_SECTION_ID=&IBLOCK_TYPE_ID=news&IBLOCK_ID=1&IBLOCK_CODE=furniture_news&IBLOCK_EXTERNAL_ID=furniture_news&CODE=','Получено прочное водостойкое соединение','Получено новое прочное водостойкое клеевое соединение.Изобретение относится к области получения и применения клеящих составов, используемых в деревообрабатывающей, мебельной и строительной промышленности. Данная клеевая композиция предназначена только для горячего прессования и имеет в своем составе многокомпонентный отвердитель. \r\n\rАвторы изобретения\r: Разиньков Егор Михайлович и Мещерякова Анна Анатольевна \rПатент Российской Федерации RU2277566\rОписание изобретения\rИзобретение относится к области получения и применения клеящих составов, используемых в деревообрабатывающей, мебельной и строительной промышленности.\rДанная клеевая композиция предназначена только для горячего прессования и имеет в своем составе многокомпонентный отвердитель. Прототипом клеевой композиции является клей, состоящий из карбамидоформальдегидной смолы, сополимера акрилонитрила с N-винилкапролактамом и отвердитель. В качестве отвердителя применяют хлористый аммоний либо акриловую кислоту. \rИзобретение решает задачу по получению прочного и водостойкого клеевого соединения.\rЭто достигается тем, что клеевая композиция, включающая синтетическую смолу и отвердитель, согласно изобретению, дополнительно содержит модификатор, причем в качестве синтетической смолы клеевая композиция включает карбамидомеламиноформальдегидную смолу с отвердителем 2542, в качестве модификатора - карбамидоформальдегидную смолу, а в качестве отвердителя - 10%-ный раствор щавелевой кислоты при следующем соотношении компонентов, мас.ч.:\rКарбамидомеламиноформальдегидная смола\r64,5-79,2\r10%-ный Раствор щавелевой кислоты\r4,4-20,5\rОтвердитель для карбамидомеламиноформальдегидной \r0,6-2,0\rсмолы 2542\r13,0-15,8','','news','1',NULL,'2010-05-27 00:00:00',NULL),(48,'2010-05-01 00:00:00','iblock','30',0,NULL,NULL,NULL,'=ID=30&EXTERNAL_ID=2&IBLOCK_SECTION_ID=&IBLOCK_TYPE_ID=vacancies&IBLOCK_ID=4&IBLOCK_CODE=furniture_vacancies&IBLOCK_EXTERNAL_ID=furniture_vacancies&CODE=','Продавец-дизайнер (кухни)','Требования\rУверенный пользователь ПК, навыки черчения от руки и в программах, опыт работы дизайнером/конструктором в мебельной сфере, этика делового общения\rОбязанности\rКонсультирование клиентов по кухонной мебели, оставление художественно-конструкторских проектов, прием и оформление заказов.\rУсловия\rЗарплата: 13500 оклад + % от личных продаж + премии‚ совокупный доход от 20000 руб,полный соц. пакет‚ оформление согласно ТК РФ','','vacancies','4',NULL,'2010-05-01 00:00:00',NULL),(49,'2010-05-01 00:00:00','iblock','31',0,NULL,NULL,NULL,'=ID=31&EXTERNAL_ID=3&IBLOCK_SECTION_ID=&IBLOCK_TYPE_ID=vacancies&IBLOCK_ID=4&IBLOCK_CODE=furniture_vacancies&IBLOCK_EXTERNAL_ID=furniture_vacancies&CODE=','Директор магазина','Требования\rВысшее образование‚ опыт руководящей работы в рознице от 3 лет‚ опытный пользователь ПК‚ этика делового общения‚ знание методов управления и заключения договоров‚ отличное знание торгового и трудового законодательств‚ ответственность‚ инициативность‚ активность.\rОбязанности\rРуководство деятельностью магазина‚ организация эффективной работы персонала магазина‚ финансово-хозяйственная деятельность и отчетность‚ выполнение плана продаж‚ отчетность.\rУсловия\rТрудоустройство по ТК РФ‚ полный соц. пакет‚ график работы 5 чере 2 (168 час/мес)‚ зарплата: оклад 28000 + % от оборота + премии‚ совокупный доход от 35000 руб','','vacancies','4',NULL,'2010-05-01 00:00:00',NULL),(50,'2010-05-01 00:00:00','iblock','32',0,NULL,NULL,NULL,'=ID=32&EXTERNAL_ID=4&IBLOCK_SECTION_ID=&IBLOCK_TYPE_ID=vacancies&IBLOCK_ID=4&IBLOCK_CODE=furniture_vacancies&IBLOCK_EXTERNAL_ID=furniture_vacancies&CODE=','Бухгалтер отдела учета готовой продукции','Требования\rЖен., 22-45, уверенный пользователь ПК, опыт работы бухгалтером приветсвуется, знание бухгалтерского учета (базовый уровень), самостоятельность, ответственность, коммуникабельность, быстрая обучаемость, желание работать.\rОбязанности\rРабота с первичными документами по учету МПЗ Ведение журналов-ордеров по производственным счетам Формирование материальных отчетов подразделений Исполнение дополнительных функций по указанию руководителя\rУсловия\rГрафик работы 5 дней в неделю, адрес работы г. Шатура, Ботинский пр-д, 37. Зарплата: оклад 10 800 р. + премия 40% от оклада, полный соц. пакет.','','vacancies','4',NULL,'2010-05-01 00:00:00',NULL),(59,'2026-01-19 13:34:34','iblock','41',0,NULL,NULL,NULL,'=ID=41&EXTERNAL_ID=56c3f2a5-a359-11f0-9593-f61e6c17d77a&IBLOCK_SECTION_ID=15&IBLOCK_TYPE_ID=catalog&IBLOCK_ID=9&IBLOCK_CODE=&IBLOCK_EXTERNAL_ID=d5c69309-148a-441c-ae6b-66bc244dacf3&CODE=','Тест Масло гидравлическое ВИПРО','Тест Масло гидравлическое ВИПРО\r\nМасло предназначено для систем гидроусилителя руля, гидрообъемных передач и гидравлических систем автомобильной техники, в том числе техники специального назначения.','','catalog','9',NULL,NULL,NULL),(60,'2026-01-27 16:41:08','iblock','42',0,NULL,NULL,NULL,'=ID=42&EXTERNAL_ID=4bd38f92-f6b7-11f0-959c-fb299729d190&IBLOCK_SECTION_ID=16&IBLOCK_TYPE_ID=catalog&IBLOCK_ID=10&IBLOCK_CODE=&IBLOCK_EXTERNAL_ID=f9079cb7-e994-43d4-9de4-ee93930dd1bd&CODE=','Кинематическая вязкость при 100°C по ГОСТ 33','Кинематическая вязкость при 100°C по ГОСТ 33\r\nКомпания Симэкс-Хим располагает аттестованной лабораторией анализа смазочных материалов, которая оснащена современным оборудованием. Специалисты компании, обладая накопленным научным опытом и знаниями в разработке, проверке и производстве смазочных материалов, обеспечивают постоянный контроль качества сырьевых компонентов и продукции, адаптацию продуктов к специфическим требованиям заказчиков, реализующих свои проекты в разных странах, географических поясах и погодных условиях.\nНаша испытательная лаборатория анализа смазочных материалов предлагает услуги по проведению анализа определения термоокислительной стабильности и коррозионной активности смазочных материалов. Данный анализ проводится согласно ГОСТ 20944-75.\n\nМетодика проведения анализа на определение термоокислительной стабильности и коррозионной активности по ГОСТ 20944-75\n\nСущность метода заключается в окислении жидкости в контакте с металлами и воздухом, с нагревом до 200°C. Термоокислительную стабильность жидкости оценивают по изменению внешнего ви','','catalog','10',NULL,NULL,NULL),(61,'2026-01-27 16:41:08','iblock','43',0,NULL,NULL,NULL,'=ID=43&EXTERNAL_ID=42f824e5-f6b8-11f0-959c-fb299729d190&IBLOCK_SECTION_ID=16&IBLOCK_TYPE_ID=catalog&IBLOCK_ID=10&IBLOCK_CODE=&IBLOCK_EXTERNAL_ID=f9079cb7-e994-43d4-9de4-ee93930dd1bd&CODE=','Кинематическая вязкость при 40°C по ГОСТ 33','Кинематическая вязкость при 40°C по ГОСТ 33\r\nКомпания Симэкс-Хим располагает аттестованной лабораторией анализа смазочных материалов, которая оснащена современным оборудованием. Специалисты компании, обладая накопленным научным опытом и знаниями в разработке, проверке и производстве смазочных материалов, обеспечивают постоянный контроль качества сырьевых компонентов и продукции, адаптацию продуктов к специфическим требованиям заказчиков, реализующих свои проекты в разных странах, географических поясах и погодных условиях.\nНаша испытательная лаборатория анализа смазочных материалов предлагает услуги по проведению анализа определения термоокислительной стабильности и коррозионной активности смазочных материалов. Данный анализ проводится согласно ГОСТ 20944-75.\n\nМетодика проведения анализа на определение термоокислительной стабильности и коррозионной активности по ГОСТ 20944-75\n\nСущность метода заключается в окислении жидкости в контакте с металлами и воздухом, с нагревом до 200°C. Термоокислительную стабильность жидкости оценивают по изменению внешнего ви','','catalog','10',NULL,NULL,NULL),(62,'2026-01-27 16:41:37','iblock','44',0,NULL,NULL,NULL,'=ID=44&EXTERNAL_ID=f300d912-fb4d-11f0-959d-9962a2f85f27&IBLOCK_SECTION_ID=18&IBLOCK_TYPE_ID=catalog&IBLOCK_ID=11&IBLOCK_CODE=&IBLOCK_EXTERNAL_ID=7f2021b0-8f6c-4123-ad5c-2f921a46b029&CODE=','Тест Масло гидравлическое SIMY HVLP-32 Бочка 170кг','Масло гидравлическое SIMY HVLP-32 Бочка 170кг\r\nВысокоэффективное гидравлическое масло, разработанное для наиболее полного соответствия специфическим требованиям эксплуатации в российских условиях современных гидравлических систем, применяющихся в промышленном оборудовании и мобильной технике.\nОтвечает требованиям EATON VICKERS, BOSCH REXROTH и немецкому стандарту DIN51524-3. \nХорошие показатели гидролитической стабильности и водоотталкивающие свойства способствуют превосходной фильтруемости при попадании воды. Антипенные присадки обеспечивают низкий уровень пенообразования, быстрый отвод воздуха, бесперебойную и эффективную работу техники.\nБлагодаря улучшенным вязкостно-температурным харктеристикам, масло сохраняет превосходную текучесть и прокачиваемость при отрицательных температурах, что позволяет обеспечить легкий пуск гидропривода.','','catalog','11',NULL,NULL,NULL),(63,'2026-01-28 10:20:10','iblock','45',0,NULL,NULL,NULL,'=ID=45&EXTERNAL_ID=56c3f2a5-a359-11f0-9593-f61e6c17d77a&IBLOCK_SECTION_ID=18&IBLOCK_TYPE_ID=catalog&IBLOCK_ID=11&IBLOCK_CODE=&IBLOCK_EXTERNAL_ID=7f2021b0-8f6c-4123-ad5c-2f921a46b029&CODE=','Тест Масло гидравлическое ВИПРО','Тест Масло гидравлическое ВИПРО\r\nМасло разработано в научном центре СИМЭКС-ХИМ по техническому заданию российских производителей автомобильной техники как аналог гидравлических жидкостей сегмента CHF/PSF премиального качества от ведущих мировых производителей смазочных материалов. Технологией изготовления масла ВИПРО предусмотрено применение уникальных присадок и специально подобранных синтетических базовых масел — полиальфаолефинов (ПАО), обеспечивающих оптимальную работу и защиту гидравлических систем. Гидравлическое синтетическое масло ВИПРО производится в строгом соответствии с:\r\n\r\nМасло ВИПРО создано для любых, в том числе экстремальных, условий эксплуатации и имеет следующие преимущества:\r\nмасло первой заливки на конвейере;\r\nподходит для легковых и грузовых автомобилей таких марок как: КАМАЗ, ГАЗ, МАЗ, Урал, MAN, Mercedes, Volvo, Scania;\r\nполностью синтетическое;\r\nработоспособно от минус 50°C до 140°C;\r\nтемпература застывания ниже минус 60°C;\r\nиндекс вязкости 315;\r\nотличная прокачиваемость в системе, даже при низких температурах;\r\nмасло не оказы','','catalog','11',NULL,NULL,NULL),(64,'2026-01-28 10:20:18','iblock','46',0,NULL,NULL,NULL,'=ID=46&EXTERNAL_ID=f300d912-fb4d-11f0-959d-9962a2f85f27&IBLOCK_SECTION_ID=20&IBLOCK_TYPE_ID=catalog&IBLOCK_ID=12&IBLOCK_CODE=&IBLOCK_EXTERNAL_ID=d680fcc8-90de-400e-ac35-e81bc4294607&CODE=','Тест Масло гидравлическое SIMY HVLP-32 Бочка 170кг','Масло гидравлическое SIMY HVLP-32 Бочка 170кг\r\nВысокоэффективное гидравлическое масло, разработанное для наиболее полного соответствия специфическим требованиям эксплуатации в российских условиях современных гидравлических систем, применяющихся в промышленном оборудовании и мобильной технике.\nОтвечает требованиям EATON VICKERS, BOSCH REXROTH и немецкому стандарту DIN51524-3. \nХорошие показатели гидролитической стабильности и водоотталкивающие свойства способствуют превосходной фильтруемости при попадании воды. Антипенные присадки обеспечивают низкий уровень пенообразования, быстрый отвод воздуха, бесперебойную и эффективную работу техники.\nБлагодаря улучшенным вязкостно-температурным харктеристикам, масло сохраняет превосходную текучесть и прокачиваемость при отрицательных температурах, что позволяет обеспечить легкий пуск гидропривода.','','catalog','12',NULL,NULL,NULL),(65,'2026-01-28 10:20:24','iblock','47',0,NULL,NULL,NULL,'=ID=47&EXTERNAL_ID=99f55350-fb4e-11f0-959d-9962a2f85f27&IBL