INSERT INTO `b_search_content_text` VALUES (1,'78ee223d369272c4c221f0d629eaa34b','WEBHOST1 - САЙТ ПРИПАРКОВАН\r\nУРА! ПОЧТИ ГОТОВО 🥳\rДОМЕН \rУСПЕШНО ПРИПАРКОВАН \rЛИЧНЫЙ КАБИНЕТ\r/ \rБАЗА ЗНАНИЙ\r/ \rКОНТАКТЫ\rРАБОТАЕТ НА БАЗЕ ПЛАТФОРМЫ \rWEBHOST1\r— НАДЕЖНЫЙ NVME SSD-ХОСТИНГ.\r\n'),(2,'55171aa121806afa21b564e0af9ed46f','ИСТОРИЯ\r\n1992Г. 								\rМЕБЕЛЬНАЯ КОМПАНИЯ\rНАЧИНАЛАСЬ С ИЗГОТОВЛЕНИЯ МЕБЕЛИ ДЛЯ ШКОЛ И ОФИСОВ. ПЕРВОЕ 									ПРОИЗВОДСТВО МЕБЕЛИ РАСПОЛАГАЛОСЬ В АРЕНДУЕМОЙ МАСТЕРСКОЙ, ПЛОЩАДЬЮ 400 М2 С ОДНИМ 									ДЕРЕВООБРАБАТЫВАЮЩИМ СТАНКОМ. В КОМПАНИИ РАБОТАЛО ДВАДЦАТЬ ЧЕЛОВЕК. ВСЕ ЗАРАБОТАННЫЕ 									СРЕДСТВА ВКЛАДЫВАЛИСЬ В РАЗВИТИЕ, ЧТО ПОЗВОЛИЛО МОЛОДОЙ КОМПАНИИ РАСТИ БЫСТРЫМИ 									ТЕМПАМИ. 								\r1993Г. 								\rВВЕДЕН В ЭКСПЛУАТАЦИЮ НОВЫЙ ЦЕХ ПЛОЩАДЬЮ 700 М2, СТАВШИЙ ПЕРВОЙ СОБСТВЕННОСТЬЮ 									\rМЕБЕЛЬНОЙ КОМПАНИИ\r. МОДЕРНИЗАЦИЯ ПРОИЗВОДСТВЕННОЙ БАЗЫ ПРЕДПРИЯТИЯ СТАЛА ХОРОШЕЙ 									ТРАДИЦИЕЙ. КОМПАНИЯ ПОСТЕПЕННО ПЕРЕШЛА К БОЛЕЕ СОВЕРШЕННОМУ ОБОРУДОВАНИЮ, ЧТО ПОЗВОЛИЛО 									ПОВЫСИТЬ УРОВЕНЬ КАЧЕСТВА ВЫПУСКАЕМОЙ ПРОДУКЦИИ И ЗНАЧИТЕЛЬНО УВЕЛИЧИТЬ ОБЪЕМЫ ПРОИЗВОДСТВА. 								\r1998Г. 								\rВ ВОРОНЕЖЕ ОТКРЫТ ПЕРВЫЙ ФИРМЕННЫЙ МАГАЗИН-САЛОН \rМЕБЕЛЬНАЯ КОМПАНИЯ\r. ШАГ ЗА ШАГОМ 									ПРОДУКЦИЯ ПРЕДПРИЯТИЯ ЗАВОЕВЫВАЛА РЕГИОНЫ СИБИРИ И УРАЛА, МОСКВЫ И ПОДМОСКОВЬЯ, 									ЮГА И СЕВЕРО-ЗАПАДА РОССИИ. ПРОИЗВОДСТВЕННЫЕ ПЛОЩАДИ КОМПАНИИ УВЕЛИЧЕНЫ ДО 5000 									М2. 								\r1999Г. 								\rМЕБЕЛЬНАЯ КОМПАНИЯ\rСТАЛА ДИПЛОМАНТОМ ОДНОЙ ИЗ САМЫХ ПРЕСТИЖНЫХ МЕЖДУНАРОДНЫХ 									ВЫСТАВОК \rЕВРОЭКСПОМЕБЕЛЬ-99\r- ПЕРВОЕ ОФИЦИАЛЬНОЕ ПРИЗНАНИЕ МЕБЕЛЬНОЙ ПРОДУКЦИИ 									МЕБЕЛЬНОЙ КОМПАНИИ. В ЭТОМ ЖЕ ГОДУ КОМПАНИЯ ВЫХОДИТ НА МИРОВОЙ РЫНОК. БЫЛ ЗАКЛЮЧЕН 									РЯД КОНТРАКТОВ НА ПОСТАВКУ МЕБЕЛИ В СТРАНЫ СНГ И БЛИЖНЕГО ЗАРУБЕЖЬЯ. 								\r2000Г. 								\rКОЛЛЕКТИВ КОМПАНИИ НАСЧИТЫВАЕТ БОЛЕЕ 500 СОТРУДНИКОВ. ЗАКЛЮЧАЮТСЯ НОВЫЕ КОНТРАКТ 									НА ПОСТАВКУ МЕБЕЛИ В ЕВРОПЕЙСКИЕ СТРАНЫ. 								\r2002Г. 								\rМЕБЕЛЬНАЯ КОМПАНИЯ\rВОШЛА В ДЕСЯТКУ ЛУЧШИХ ПРОИЗВОДИТЕЛЕЙ МЕБЕЛИ ПО ДАННЫМ ВЕДУЩИХ 									МЕБЕЛЬНЫХ САЛОНОВ РОССИИ, А ТАКЖЕ В ЧИСЛО ЛИДЕРОВ ОРГАНИЗАЦИОННОГО РАЗВИТИЯ. 								\r2003Г. 								\rПРИСТУПИЛИ К СТРОИТЕЛЬСТВУ СКЛАДА МАТЕРИАЛОВ. В МОСКВЕ ОТКРЫТ ФИЛИАЛ КОМПАНИИ. \nПРОВЕДЕНА ПЕРВАЯ КОНФЕРЕНЦИЯ ПАРТНЕРОВ, РЕЗУЛЬТАТОМ КОТОРОЙ СТАЛО УКРЕПЛЕНИЕ ВЗАИМОВЫГОДНЫХ 									ОТНОШЕНИЙ И ЗАКЛЮЧЕНИЕ ДИЛЕРСКИХ ДОГОВОРОВ. 								\r2004Г. 								\rЗАВЕРШЕНО СТРОИТЕЛЬСТВО И ОСНАЩЕНИЕ НОВОГО ПРОИЗВОДСТВЕННОГО КОРПУСА И СКЛАДА МАТЕРИАЛОВ. \nРАСШИРЕНО ПРЕДСТАВИТЕЛЬСТВО КОМПАНИИ НА РОССИЙСКОМ РЫНКЕ И ЗА РУБЕЖОМ. \nОТКРЫТО 									РЕГИОНАЛЬНОЕ ПРЕДСТАВИТЕЛЬСТВО \rМЕБЕЛЬНОЙ КОМПАНИИ\rВ ЕКАТЕРИНБУРГЕ. 								\r2005Г. 								\rКОМПАНИЯ ПРИОБРЕТАЕТ НОВОЕ ПРОИЗВОДСТВЕННОЕ ОБОРУДОВАНИЕ КОНЦЕРНА - УГЛОВУЮ ЛИНИЮ 									РАСКРОЯ МАТЕРИАЛОВ И ЛИНИЮ ЗАГРУЗКИ ВЫГРУЗКИ. \nНАЧИНАЕТСЯ ВЫПУСК ПРОДУКЦИИ В 									НАТУРАЛЬНОМ ШПОНЕ. ФОРМИРУЕТСЯ ОТДЕЛЬНЫЙ СКЛАД МАТЕРИАЛОВ И КОМПЛЕКТУЮЩИХ. \nВ ЭТОМ ЖЕ ГОДУ ОТКРЫВАЕТСЯ ФАБРИКА МЯГКОЙ МЕБЕЛИ \rМЕБЕЛЬПЛЮС\r2006Г. 								\rОТКРЫТЫ РЕГИОНАЛЬНЫЕ ПРЕДСТАВИТЕЛЬСТВА \rМЕБЕЛЬНОЙ КОМПАНИИ\rВ САНКТ-ПЕТЕРБУРГЕ 									И НИЖНЕМ НОВГОРОДЕ. \nРАЗВИВАЕТСЯ СОБСТВЕННАЯ РОЗНИЧНАЯ СЕТЬ ФИРМЕННЫХ МАГАЗИНОВ-САЛОНОВ 									НА ТЕРРИТОРИИ РОССИИ. 								\r2007Г. 								\rЗАВЕРШЕНО СТРОИТЕЛЬСТВО ВТОРОЙ ФАБРИКИ. ОБЩАЯ ПЛОЩАДЬ ПРОИЗВОДСВЕННО-СКЛАДСКИХ КОРПУСОВ 									КОМПАНИИ СОСТАВЛЯЕТ УЖЕ БОЛЕЕ 30000 М2. \nПРОВЕДЕНА ВТОРАЯ КОНФЕРЕНЦИЯ ПАРТНЕРОВ 									КОМПАНИИ \r\"ТЕХНОЛОГИЯ УСПЕШНОГО БИЗНЕСА\"\r. 								\r2008Г. 								\rОТКРЫТО НОВОЕ ПРЕДПРИЯТИЕ ДЛЯ ПРОИЗВОДСТВА МЕБЕЛИ ПО ИНДИВИДУАЛЬНЫМ ПРОЕКТАМ \rКОМФОРТ\r. \nМЕБЕЛЬНАЯ КОМПАНИЯ\rПРОДОЛЖАЕТ ОБНОВЛЕНИЕ ОБОРУДОВАНИЯ. 								\r2008Г. 								\rНОВЕЙШИМ ОБОРУДОВАНИЕМ УКОМПЛЕКТОВАНА ВТОРАЯ ФАБРИКА. ЗАПУЩЕНА ВТОРАЯ ПРОИЗВОДСТВЕННАЯ 									ЛИНИЯ. \nПРОВЕДЕНА ТРЕТЬЯ КОНФЕРЕНЦИЯ \rПАРТНЕРСТВО - БИЗНЕС СЕГОДНЯ\rПРИНЯТО РЕШЕНИЕ О СТРОИТЕЛЬСТВЕ ТРЕТЬЕЙ ФАБРИКИ. ПЛОЩАДЬ ПРОИЗВОДСТВЕННО  СКЛАДСКИХ 									КОРПУСОВ СОСТАВИТ БОЛЕЕ 70000М2. \nПО ВСЕЙ СТРАНЕ И ЗАРУБЕЖОМ ОТКРЫТО 37 МЕБЕЛЬНЫХ 									САЛОНОВ. \nВ КОМПАНИИ РАБОТАЕТ БОЛЕЕ ПОЛУТОРА ТЫСЯЧ СОТРУДНИКОВ.\r\n'),(3,'b535d9cb75c64e695d6ebad33b22d99c','О КОМПАНИИ\r\nНАША КОМПАНИЯ СУЩЕСТВУЕТ НА РОССИЙСКОМ РЫНКЕ С 1992 ГОДА. ЗА ЭТО ВРЕМЯ \rМЕБЕЛЬНАЯ КОМПАНИЯ\rПРОШЛА БОЛЬШОЙ ПУТЬ ОТ МАЛЕНЬКОЙ ТОРГОВОЙ ФИРМЫ ДО ОДНОГО ИЗ КРУПНЕЙШИХ ПРОИЗВОДИТЕЛЕЙ КОРПУСНОЙ МЕБЕЛИ В РОССИИ. 						 \rГЛАВНОЕ ПРАВИЛО - ИНДИВИДУАЛЬНЫЙ ПОДХОД К КАЖДОМУ КЛИЕНТУ\rНА СЕГОДНЯШНИЙ ДЕНЬ НАМИ РАЗРАБОТАНО БОЛЕЕ ПЯТИСОТ МОДЕЛЕЙ ДЛЯ ОФИСА И ДОМА. ВМЕСТЕ С ТЕМ МЫ СТРЕМИМСЯ ОБЕСПЕЧИТЬ НЕПОВТОРИМОСТЬ СВОЕЙ ПРОДУКЦИИ. МЫ ИЗГОТОВИМ МЕБЕЛЬ ДЛЯ КУХНИ, ДЕТСКОЙ, ГОСТИНОЙ, СПАЛЬНОЙ ИЛИ ВАННОЙ КОМНАТЫ, МЕБЕЛЬ ДЛЯ ОФИСА ОСОБОГО ДИЗАЙНА И НЕСТАНДАРТНОГО РАЗМЕРА. \rНАШИ ДИЗАЙНЕРЫ ПРОИЗВЕДУТ ЗАМЕРЫ ПОМЕЩЕНИЯ И ВМЕСТЕ С ВАМИ РАЗРАБОТАЮТ ДИЗАЙН-ПРОЕКТ МЕБЕЛИ ДЛЯ ВАШЕГО ИНТЕРЬЕРА, ПОДОБРАВ С ВЫСОКОЙ ТОЧНОСТЬЮ РАЗМЕРЫ, МОДЕЛИ, ЦВЕТА, ПОМОГУТ ОПТИМАЛЬНО РАСПОЛОЖИТЬ МЕБЕЛЬ. \rВАШ ПРОЕКТ БУДЕТ СОЗДАН С УЧЕТОМ ВСЕХ НЮАНСОВ И ПРОРИСОВКОЙ МЕЛЬЧАЙШИХ ДЕТАЛЕЙ. РЕЗУЛЬТАТЫ СОВМЕСТНОГО ТВОРЧЕСТВА ВЫ СМОЖЕТЕ ПОСМОТРЕТЬ В ОБЪЕМНОМ ПРЕДСТАВЛЕНИИ. ВАМ НАГЛЯДНО ПРОДЕМОНСТРИРУЮТ, КАК БУДУТ ВЫГЛЯДЕТЬ В ЖИЗНИ ВЫБРАННЫЕ ЭЛЕМЕНТЫ ИНТЕРЬЕРА ПРИ РАЗНОМ ОСВЕЩЕНИИ, В КОНКРЕТНОМ ПОМЕЩЕНИИ, СДЕЛАННЫЕ ИЗ ОПРЕДЕЛЕННЫХ МАТЕРИАЛОВ. В ВАШЕ РАСПОРЯЖЕНИЕ БУДЕТ ПРЕДОСТАВЛЕНО МНОГО РАЗЛИЧНЫХ ВАРИАНТОВ, ИЗ КОТОРЫХ ВЫ СМОЖЕТЕ ВЫБРАТЬ НАИБОЛЕЕ ПОДХОДЯЩИЙ ИМЕННО ВАМ. 						 					\rЗАКАЗ БУДЕТ ВЫПОЛНЕН И ДОСТАВЛЕН ТОЧНО В СРОК. ВСЕ РАБОТЫ ПО СБОРКЕ И УСТАНОВКЕ МЕБЕЛИ ОСУЩЕСТВЛЯЮТ СОТРУДНИКИ НАШЕЙ КОМПАНИИ. СТРОГИЙ КОНТРОЛЬ КАЧЕСТВА ОСУЩЕСТВЛЯЕТСЯ НА ВСЕХ ЭТАПАХ РАБОТ: ОТ МОМЕНТА ОФОРМЛЕНИЯ ЗАКАЗА ДО МОМЕНТА ПРИЕМА ВЫПОЛНЕННЫХ РАБОТ. \rПЕРЕДОВЫЕ ТЕХНОЛОГИИ И БЕСЦЕННЫЙ ОПЫТ\rИСПОЛЬЗОВАНИЕ ПЕРЕДОВЫХ КОМПЬЮТЕРНЫХ ТЕХНОЛОГИЙ, МНОГОЛЕТНИЙ ОПЫТ НАШИХ СПЕЦИАЛИСТОВ ПОЗВОЛЯЮТ ПРОИЗВЕСТИ ГРАМОТНЫЕ РАСЧЕТЫ И СНИЗИТЬ РАСХОД МАТЕРИАЛОВ И СЕБЕСТОИМОСТЬ ПРОДУКЦИИ, ИЗБЕЖАТЬ ОШИБОК ПРИ ПРОЕКТИРОВАНИИ И ОПТИМИЗИРОВАТЬ ДИЗАЙН КОМПЛЕКСНЫХ ИНТЕРЬЕРОВ. ГАРАНТИЯ НА НАШУ ПРОДУКЦИЮ СОСТАВЛЯЕТ 18 МЕСЯЦЕВ, А НА ОТДЕЛЬНУЮ ПРОДУКЦИЮ 36 МЕСЯЦЕВ. \rМЫ ГОРДИМСЯ НАШИМИ СОТРУДНИКАМИ ПРОШЕДШИМИ ПРОФЕССИОНАЛЬНОЕ ОБУЧЕНИЕ В ЛУЧШИХ УЧЕБНЫХ ЗАВЕДЕНИЯХ РОССИИ И ЗАРУБЕЖЬЯ. У НАС ТРУДЯТСЯ ВЫСОКОКЛАССНЫЕ СПЕЦИАЛИСТЫ РАЗНЫХ ВОЗРАСТОВ. МЫ ЦЕНИМ ЭНТУЗИАЗМ МОЛОДЕЖИ И БЕСЦЕННЫЙ ОПЫТ СТАРШЕГО ПОКОЛЕНИЯ. ВСЕ МЫ РАЗНЫЕ, НО НАС ОБЪЕДИНЯЕТ ПРЕДАННОСТЬ СВОЕМУ ДЕЛУ И ВЕРА В ИДЕИ НАШЕЙ КОМПАНИИ. \rВЫСОЧАЙШИЕ СТАНДАРТЫ КАЧЕСТВА - ЗАЛОГ НАШЕГО УСПЕХА\rМЕБЕЛЬНАЯ КОМПАНИЯ\rОСУЩЕСТВЛЯЕТ ПРОИЗВОДСТВО МЕБЕЛИ НА ВЫСОКОКЛАССНОМ ОБОРУДОВАНИИ С ПРИМЕНЕНИЕМ МИНИМАЛЬНОЙ ДОЛИ РУЧНОГО ТРУДА, ЧТО ПОЗВОЛЯЕТ ОБЕСПЕЧИТЬ ВЫСОКОЕ КАЧЕСТВО НАШЕЙ ПРОДУКЦИИ. НАЛАЖЕН ПРОИЗВОДСТВЕННЫЙ ПРОЦЕСС КАК МАССОВОГО И ИНДИВИДУАЛЬНОГО ХАРАКТЕРА, ЧТО С ОДНОЙ СТОРОНЫ ПОЗВОЛЯЕТ ОБЕСПЕЧИТЬ ПОСТОЯННУЮ НОМЕНКЛАТУРУ ИЗДЕЛИЙ И ИНДИВИДУАЛЬНЫЙ ПОДХОД  С ДРУГОЙ. \rЕЖЕГОДНО НАША ПРОДУКЦИЯ ПРОХОДИТ СЕРТИФИКАЦИОННЫЕ ИСПЫТАНИЯ В СПЕЦИАЛИЗИРОВАННЫХ ЛАБОРАТОРИЯХ РОССИИ И ИМЕЕТ СЕРТИФИКАТЫ СООТВЕТСТВИЯ ПРОДУКЦИИ НОРМАМ БЕЗОПАСНОСТИ И КАЧЕСТВА. КРОМЕ ТОГО, \rМЕБЕЛЬНАЯ КОМПАНИЯ\rОДНОЙ ИЗ ПЕРВЫХ СРЕДИ МЕБЕЛЬНЫХ ПРОИЗВОДИТЕЛЕЙ РОССИИ В 2003 ГОДУ ПРОШЛА АУДИТ НА СООТВЕТСТВИЕ ТРЕБОВАНИЯМ СИСТЕМЫ МЕНЕДЖМЕНТА КАЧЕСТВА ИСО 9000 И ПОЛУЧИЛА СЕРТИФИКАТ СООТВЕТСТВИЯ СИСТЕМЫ КАЧЕСТВА НА ПРЕДПРИЯТИИ НОРМАМ МЕЖДУНАРОДНОГО СТАНДАРТА.\r\n'),(4,'c501a4fb29fd5bc92bc4babebf160ed9','РУКОВОДСТВО\r\nУСПЕШНОЕ РАЗВИТИЕ БИЗНЕСА  ВО МНОГОМ РЕЗУЛЬТАТ КВАЛИФИЦИРОВАННОЙ РАБОТЫ РУКОВОДСТВА. 							\rМЕБЕЛЬНАЯ КОМПАНИЯ\rНА МЕБЕЛЬНОМ РЫНКЕ УЖЕ 18 ЛЕТ. ЗА ЭТО ВРЕМЯ КОМПАНИЯ 							НЕ ТОЛЬКО СОХРАНИЛА, НО И УПРОЧИЛА ЛИДИРУЮЩИЕ ПОЗИЦИИ СРЕДИ ВЕДУЩИХ ИГРОКОВ МЕБЕЛЬНОГО 							РЫНКА. 						\rМЕБЕЛЬНАЯ КОМПАНИЯ\rИЗ ГОДА В ГОД РАСШИРЯЕТ АССОРТИМЕНТ ВЫПУСКАЕМОЙ ПРОДУКЦИИ, 							НАРАЩИВАЕТ ТЕМПЫ И ОБЪЕМЫ ПРОИЗВОДСТВА, УВЕЛИЧИВАЕТ ПРОИЗВОДСТВЕННЫЕ И СКЛАДСКИЕ 							ПЛОЩАДИ, РАЗВИВАЕТ ОТНОШЕНИЯ С ПАРТНЕРАМИ СО ВСЕХ РЕГИОНОВ СТРАНЫ И НАЛАЖИВАЕТ СВЯЗИ 							С ЗАРУБЕЖНЫМИ ПАРТНЕРАМИ. В БОЛЬШОЙ СТЕПЕНИ ЭТО ЗАСЛУГА ХОРОШО ПОДГОТОВЛЕННОГО РУКОВОДЯЩЕГО 							СОСТАВА И ЕГО ГРАМОТНОЙ ПОЛИТИКИ. 						\rСОБСТВЕННИК КОМПАНИИ МЕБЕЛЬНАЯ КОМПАНИЯ\rКОЛЕСНИКОВ ВИКТОР ФЕДОРОВИЧ 								\rРОДИЛСЯ 3 СЕНТЯБРЯ 1964 ГОДА.\nОБРАЗОВАНИЕ: ЗАКОНЧИЛ АВИАЦИОННЫЙ ФАКУЛЬТЕТ ВОРОНЕЖСКОГО 									ГОСУДАРСТВЕННОГО ПОЛИТЕХНИЧЕСКОГО ИНСТИТУТА. В 1994 ГОДУ ПРОШЕЛ ОБУЧЕНИЕ ПО ПРОГРАММЕ 									ПОДГОТОВКА МАЛОГО И СРЕДНЕГО БИЗНЕСА В США.\nВ НАСТОЯЩЕЕ ВРЕМЯ ВИКТОР ФЕДОРОВИЧ 									ВОЗГЛАВЛЯЕТ УПРАВЛЯЮЩУЮ КОМПАНИЮ, КОТОРАЯ КООРДИНИРУЕТ ДЕЯТЕЛЬНОСТЬ ПРЕДПРИЯТИЙ, 									ВХОДЯЩИХ В ГРУППУ КОМПАНИЙ \rМЕБЕЛЬНАЯ КОМПАНИЯ\r. 								\rГЕНЕРАЛЬНЫЙ ДИРЕКТОР МЕБЕЛЬНОЙ КОМПАНИИ\rРАТЧЕНКО АЛЕКСАНДР ПЕТРОВИЧ 								\rРОДИЛСЯ 5 ИЮНЯ 1962 ГОДА.\nОБРАЗОВАНИЕ: ВОРОНЕЖСКИЙ ПОЛИТЕХНИЧЕСКИЙ ИНСТИТУТ 									ПО СПЕЦИАЛЬНОСТИ ИНЖЕНЕР-ТЕХНОЛОГ; ПРОГРАММА ЭФФЕКТИВНОЕ РАЗВИТИЕ ПРОИЗВОДСТВА 									(США).\nВ \rМЕБЕЛЬНОЙ КОМПАНИИ\rСЕРГЕЙ ФОМИЧ С 1994 ГОДА. ЗА ЭТО ВРЕМЯ ПРОШЕЛ 									ПУТЬ ОТ НАЧАЛЬНИКА ЦЕХА ДО ГЕНЕРАЛЬНОГО ДИРЕКТОРА ПРЕДПРИЯТИЯ. 								\rЗАМЕСТИТЕЛЬ ГЕНЕРАЛЬНОГО ДИРЕКТОРА УПРАВЛЯЮЩЕЙ КОМПАНИИ\rРОГОВОЙ АНДРЕЙ ВЛАДИМИРОВИЧ 								\rОБРАЗОВАНИЕ: ФАКУЛЬТЕТ РАДИОТЕХНИКИ ВОРОНЕЖСКОГО ГОСУДАРСТВЕННОГО ТЕХНИЧЕСКОГО УНИВЕРСИТЕТА.\nВ КОМПАНИИ С 1 ИЮНЯ 2000 ГОДА.\r\n'),(5,'17e08217818f62561b1d2f0f3a016a1f','МИССИЯ И СТРАТЕГИЯ\r\nМЕБЕЛЬНАЯ КОМПАНИЯ\r- ДИНАМИЧНО РАЗВИВАЮЩЕЕСЯ ПРОИЗВОДСТВЕННОЕ 							ПРЕДПРИЯТИЕ, КОТОРОЕ ИМЕЕТ ПЕРЕД СОБОЙ \nЯСНО ВЫРАЖЕННЫЕ ЦЕЛИ И ИНСТРУМЕНТЫ ДЛЯ 							ИХ ДОСТИЖЕНИ.МЫ ПРЕДОСТАВЛЯЕМ КАЖДОМУ ЛУЧШУЮ ВОЗМОЖНОСТЬ ОБУСТРОИТЬ СВОЕ ЖИЗНЕННОЕ \nИ РАБОЧЕЕ ПРОСТРАНСТВО.МЫ РАБОТАЕМ НА ДОЛГОСРОЧНУЮ ПЕРСПЕКТИВУ И ПРЕДЛАГАЕМ ОПТИМАЛЬНЫЕ 							РЕШЕНИЯ. КОМПАНИЯ \rМЕБЕЛЬНАЯ КОМПАНИЯ\r- \nНАДЕЖНЫЙ, ТЕХНОЛОГИЧНЫЙ, ГИБКИЙ ПОСТАВЩИК 							С БОЛЬШИМИ МОЩНОСТЯМИ. 						\rЦЕЛИ И ЗАДАЧИ\rОПРАВДЫВАТЬ ОЖИДАНИЯ ЗАКАЗЧИКА: КЛИЕНТ ВСЕГДА ПРАВ. ТОЛЬКО ПОТРЕБИТЕЛЬ ФОРМИРУЕТ 									ЕДИНУЮ СИСТЕМУ ВЗГЛЯДОВ НА КАЧЕСТВО \nВЫПУСКАЕМОЙ ПРОДУКЦИИ И РАБОТ.\rДОБИТЬСЯ ОТ РАБОТНИКОВ КОМПАНИИ ПОНИМАНИЯ ИХ ЛИЧНОЙ ОТВЕТСТВЕННОСТИ ЗА КАЧЕСТВО 									РАБОТ.\rПУТЕМ ПОВЫШЕНИЯ КАЧЕСТВА ПРОДУКЦИИ И РАБОТ ПОСТОЯННО УВЕЛИЧИВАТЬ ОБЪЕМЫ ПРОИЗВОДСТВА 									С ЦЕЛЬЮ ПОСЛЕДУЮЩЕГО РЕИНВЕСТИРОВАНИЯ \nПРИБЫЛИ В РАЗВИТИЕ КОМПАНИИ.\rОБЕСПЕЧИВАТЬ СТРОГОЕ СООТВЕТСТВИЕ ПРОИЗВОДИМОЙ ПРОДУКЦИИ ТРЕБОВАНИЯМ ПОТРЕБИТЕЛЕЙ, 									НОРМАМ И ПРАВИЛАМ \nБЕЗОПАСНОСТИ, ТРЕБОВАНИЯМ ЗАЩИТЫ ОКРУЖАЮЩЕЙ СРЕДЫ.\rПОЛИТИКА КОМПАНИИ\rПОСТОЯННОЕ СОВЕРШЕНСТВОВАНИЕ СИСТЕМЫ КАЧЕСТВА. СВОЕВРЕМЕННОЕ И ЭФФЕКТИВНОЕ ПРИНЯТИЕ 									КОРРЕКТИРУЮЩИХ МЕР .\rЗАБОТА О РАБОТНИКАХ КОМПАНИИ. СОЗДАНИЕ УСЛОВИЙ ТРУДА И ОСНАЩЕНИЕ РАБОЧИХ МЕСТ, СООТВЕТСТВУЮЩИХ 									ВСЕМ САНИТАРНЫМ \nИ ГИГИЕНИЧЕСКИМ НОРМАМ.\rПОВЫШЕНИЕ БЛАГОСОСТОЯНИЯ СОТРУДНИКОВ. ОБЕСПЕЧЕНИЕ МОРАЛЬНОГО И МАТЕРИАЛЬНОГО УДОВЛЕТВОРЕНИЯ 									РАБОТНИКОВ КОМПАНИИ.\rСИСТЕМАТИЧЕСКОЕ ОБУЧЕНИЕ РАБОТНИКОВ ВСЕХ УРОВНЕЙ С ЦЕЛЬЮ ПОСТОЯННОГО ПОВЫШЕНИЯ ИХ 									ПРОФЕССИОНАЛЬНОГО МАСТЕРСТВА.\rВНЕДРЕНИЕ ВЫСОКОПРОИЗВОДИТЕЛЬНОГО ОБОРУДОВАНИЯ И НОВЕЙШИХ ТЕХНОЛОГИЙ ДЛЯ ПОВЫШЕНИЯ 									ПРОИЗВОДИТЕЛЬНОСТИ ТРУДА, \nОПТИМИЗАЦИИ ЗАТРАТ И, КАК РЕЗУЛЬТАТ, СНИЖЕНИЯ ЦЕН 									НА ВЫПУСКАЕМУЮ ПРОДУКЦИЮ.\rСОЗДАНИЕ НОВЫХ РАБОЧИХ МЕСТ. ПРИВЛЕЧЕНИЕ НА РАБОТУ СПЕЦИАЛИСТОВ ВЫСОКОЙ КВАЛИФИКАЦИИ.\rВЫХОД НА МЕЖДУНАРОДНЫЙ РЫНОК.\rМЫ РАЗВИВАЕМ ДОВЕРИТЕЛЬНЫЕ ВЗАИМОВЫГОДНЫЕ ОТНОШЕНИЯ СО СВОИМИ ПАРТНЕРАМИ В ДОЛГОСРОЧНЫХ 							ИНТЕРЕСАХ НАШЕГО БИЗНЕСА. \nМЕБЕЛЬНАЯ КОМПАНИЯ\rОТВЕТСТВЕННО ОТНОСИТСЯ 							К ВЫПОЛНЕНИЮ ВЗЯТЫХ НА СЕБЯ ОБЯЗАТЕЛЬСТВ И ЖДЕТ ТАКОГО ЖЕ \nПОДХОДА К ДЕЛУ ОТ 							СВОИХ ПАРТНЕРОВ ПО БИЗНЕСУ. ЭТА ТРЕБОВАТЕЛЬНОСТЬ  ЗАЛОГ НАШЕЙ ДОЛГОСРОЧНОЙ ПРИБЫЛЬНОСТИ. 						\rСО ДНЯ СВОЕГО ОСНОВАНИЯ \rМЕБЕЛЬНАЯ КОМПАНИЯ\rСОДЕЙСТВУЕТ РОСТУ БЛАГОСОСТОЯНИЯ 							РЕГИОНОВ РОССИИ. МЫ ПОНИМАЕМ ВАЖНОСТЬ \nСОЦИАЛЬНОЙ ОТВЕТСТВЕННОСТИ НАШЕЙ КОМПАНИИ 							И ОСТАНЕМСЯ ПРИМЕРОМ В ВОПРОСАХ СОЦИАЛЬНОЙ ЗАЩИЩЕННОСТИ НАШИХ СОТРУДНИКОВ.\r\n'),(6,'d6ae18283686e0f65091531174c8b418','ВАКАНСИИ\r\n\r\n'),(7,'d63c4b77cf485102f232c0d0d27f8bc3','КОНТАКТЫ\r\nОБРАТИТЕСЬ К НАШИМ СПЕЦИАЛИСТАМ И ПОЛУЧИТЕ ПРОФЕССИОНАЛЬНУЮ КОНСУЛЬТАЦИЮ ПО ВОПРОСАМ СОЗДАНИЯ И ПОКУПКИ МЕБЕЛИ (ОТ ДИЗАЙНА, РАЗРАБОТКИ ТЕХНИЧЕСКОГО ЗАДАНИЯ ДО ДОСТАВКИ МЕБЕЛИ К ВАМ ДОМОЙ).\rВЫ МОЖЕТЕ ОБРАТИТЬСЯ К НАМ ПО ТЕЛЕФОНУ, ПО ЭЛЕКТРОННОЙ ПОЧТЕ ИЛИ ДОГОВОРИТЬСЯ О ВСТРЕЧЕ В НАШЕМ ОФИСЕ. БУДЕМ РАДЫ ПОМОЧЬ ВАМ И ОТВЕТИТЬ НА ВСЕ ВАШИ ВОПРОСЫ. \rТЕЛЕФОНЫ\rТЕЛЕФОН/ФАКС:\n(495) 212-85-06\rТЕЛЕФОНЫ:\n(495) 212-85-07\r(495) 212-85-08\rEMAIL\rINFO@EXAMPLE.RU\r ОБЩИЕ ВОПРОСЫ\rSALES@EXAMPLE.RU\r ПРИОБРЕТЕНИЕ ПРОДУКЦИИ\rMARKETING@EXAMPLE.RU\r МАРКЕТИНГ/МЕРОПРИЯТИЯ/PR\rОФИС В МОСКВЕ\r\n'),(8,'7c285f6a61d238a340b43f0ef846a536','ВХОД НА САЙТ\r\nВЫ ЗАРЕГИСТРИРОВАНЫ И УСПЕШНО АВТОРИЗОВАЛИСЬ.\rВЕРНУТЬСЯ НА ГЛАВНУЮ СТРАНИЦУ\r\n'),(9,'626a5d1bd18fcc622fbe4e4e3619a88a','НОВОСТИ\r\n\r\n'),(11,'f58e028735b5d07233c4a161c9231405','ПОИСК\r\n\r\n'),(12,'be3fe2336ca014ea48484837a6379cf7','КАРТА САЙТА\r\n\r\n'),(14,'9dc81310e5f6940cd74425623ed50b52','МЕБЕЛЬНАЯ КОМПАНИЯ\r\nНАША КОМПАНИЯ СУЩЕСТВУЕТ НА РОССИЙСКОМ РЫНКЕ С 1992 ГОДА. ЗА ЭТО ВРЕМЯ «МЕБЕЛЬНАЯ КОМПАНИЯ» ПРОШЛА БОЛЬШОЙ ПУТЬ ОТ МАЛЕНЬКОЙ ТОРГОВОЙ ФИРМЫ ДО ОДНОГО ИЗ КРУПНЕЙШИХ ПРОИЗВОДИТЕЛЕЙ КОРПУСНОЙ МЕБЕЛИ В РОССИИ.\n«МЕБЕЛЬНАЯ КОМПАНИЯ» ОСУЩЕСТВЛЯЕТ ПРОИЗВОДСТВО МЕБЕЛИ НА ВЫСОКОКЛАССНОМ ОБОРУДОВАНИИ С ПРИМЕНЕНИЕМ МИНИМАЛЬНОЙ ДОЛИ РУЧНОГО ТРУДА, ЧТО ПОЗВОЛЯЕТ ОБЕСПЕЧИТЬ ВЫСОКОЕ КАЧЕСТВО НАШЕЙ ПРОДУКЦИИ. НАЛАЖЕН ПРОИЗВОДСТВЕННЫЙ ПРОЦЕСС КАК МАССОВОГО И ИНДИВИДУАЛЬНОГО ХАРАКТЕРА, ЧТО С ОДНОЙ СТОРОНЫ ПОЗВОЛЯЕТ ОБЕСПЕЧИТЬ ПОСТОЯННУЮ НОМЕНКЛАТУРУ ИЗДЕЛИЙ И ИНДИВИДУАЛЬНЫЙ ПОДХОД – С ДРУГОЙ.\nНАША ПРОДУКЦИЯ\rНАШИ УСЛУГИ\r\n'),(15,'92742420ff489208277435770b2dba28','МЕБЕЛЬНЫЙ ФОРУМ БЕЛАРУСИ\r\nС 20 ПО 23 АПРЕЛЯ 2010 ГОДА СОСТОИТСЯ \rМЕБЕЛЬНЫЙ ФОРУМ БЕЛАРУСИ\r ВАЖНЕЙШЕЕ МЕРОПРИЯТИИ ОТРАСЛИ В ТЕКУЩЕМ ГОДУ.\r\n\rС 20 ПО 23 АПРЕЛЯ 2010 ГОДА СОСТОИТСЯ \rМЕБЕЛЬНЫЙ ФОРУМ БЕЛАРУСИ\r ВАЖНЕЙШЕЕ МЕРОПРИЯТИИ ОТРАСЛИ В ТЕКУЩЕМ ГОДУ. В ЭКСПОЗИЦИИ ПРИНИМАЮТ УЧАСТИЕ СВЫШЕ 160 КОМПАНИЙ ИЗ \rБЕЛАРУСИ, АВСТРИИ, ЛАТВИИ, ЛИТВЫ, РОССИИ, ПОЛЬШИ \rИ\rУКРАИНЫ\r. В СОСТАВЕ ФОРУМА СОСТОИТСЯ ПЯТЬ ВЫСТАВОК:\"МИНСКИЙ МЕБЕЛЬНЫЙ САЛОН\", \"МЕБЕЛЬНЫЕ ТЕХНОЛОГИИ\", \"ОФИСКОМФОРТ\", \"КУХНЯ\" И \"ДОМОТЕХ\". ЭКСПОЗИЦИЯ БУДЕТ СТРОИТЬСЯ ПО ПРИНЦИПУ ДВУХ ТЕМАТИЧЕСКИХ СЕКТОРОВ:\rГОТОВОЙ МЕБЕЛИ\rИ \rМАТЕРИАЛОВ ДЛЯ ЕЕ ПРОИЗВОДСТВА\r.\rВ СЕКТОРЕ ГОТОВОЙ МЕБЕЛИ БУДУТ ПРЕДСТАВЛЕНЫ:\rКОРПУСНАЯ И МЯГКАЯ МЕБЕЛЬ;\rМЕБЕЛЬ ДЛЯ ДЕТЕЙ И МОЛОДЕЖИ;\rПРЕДМЕТЫ ИНТЕРЬЕРА;\rКУХОННАЯ МЕБЕЛЬ;\rМЕБЕЛЬ ДЛЯ ОФИСА И АДМИНИСТРАТИВНЫХ ЗДАНИЙ.\rВ СЕКТОРЕ МАТЕРИАЛОВ ДЛЯ ПРОИЗВОДСТВА МЕБЕЛИ БУДУТ ДЕМОНСТРИРОВАТЬСЯ НОВИНКИ РЫНКА МЕБЕЛЬНОЙ ФУРНИТУРЫ, МАТЕРИАЛОВ, ОБИВОЧНЫХ ТКАНЕЙ, ЭЛЕМЕНТОВ И АКСЕССУАРОВ ДЛЯ ПРОИЗВОДСТВА МЕБЕЛИ.\rПОМИМО РАСШИРЕННОЙ ЭКСПОЗИЦИИ ПЯТИ ТЕМАТИЧЕСКИХ ВЫСТАВОК \"ЭКСПОФОРУМ\" ПОДГОТОВИЛ РАЗНООБРАЗНУЮ ДЕЛОВУЮ ПРОГРАММУ МЕБЕЛЬНОГО ФОРУМА. В РАМКАХ ВЫСТАВКИ СОСТОЯТСЯ СЕМИНАРЫ И МАСТЕР-КЛАССЫ. И ПОИСТИНЕ МАСШТАБНЫМ В ЭТОМ ГОДУ ОБЕЩАЕТ СТАТЬ РЕСПУБЛИКАНСКИЙ КОНКУРС ФОРУМА \"\rНАРОДНОЕ ПРИЗНАНИЕ\r\". В ЭТОМ ГОДУ ОН ВЫХОДИТ ЗА РАМКИ ВЫСТАВКИ И СТАНОВИТСЯ РЕСПУБЛИКАНСКИМ СМОТРОМ ОБРАЗЦОВ МЕБЕЛИ.\rМЕБЕЛЬНЫЙ ФОРУМ\rПРЕДОСТАВЛЯЕТ СПЕЦИАЛИСТАМ ВОЗМОЖНОСТЬ ПОЗНАКОМИТЬСЯ С ТЕНДЕНЦИЯМИ МЕБЕЛЬНОЙ МОДЫ, ПРОВЕСТИ ПЕРЕГОВОРЫ, ПОЛУЧИТЬ ПРАКТИЧЕСКИЕ ПРЕДЛОЖЕНИЯ РЫНКА, УВИДЕТЬ ПЕРСПЕКТИВЫ РАЗВИТИЯ И НОВЫЕ КОНКУРЕНТНЫЕ ПРЕИМУЩЕСТВА. ВПЕРВЫЕ ДЛЯ УЧАСТНИКОВ КОНКУРСА БУДЕТ ПОДГОТОВЛЕН МАРКЕТИНГОВЫЙ ОТЧЕТ ПО РЕЗУЛЬТАТАМ ОПРОСА ПОСЕТИТЕЛЕЙ ВЫСТАВОК \rМЕБЕЛЬНОГО ФОРУМА\r.\rПРИЕМ ЗАЯВОК НА УЧАСТИЕ В КОНКУРСЕ ОСУЩЕСТВЛЯЕТСЯ ДО 12 АПРЕЛЯ 2010 ГОДА.\r\n'),(16,'d28b14fc723b19c85e2a5f17daa89898','МЕЖДУНАРОДНАЯ МЕБЕЛЬНАЯ ВЫСТАВКА SALON DEL MOBILE\r\nВ 2010 ГОДУ ВЫСТАВКА SALON DEL MOBILE ОБЕЩАЕТ БЫТЬ ЕЩЕ БОЛЕЕ РАСШИРЕННОЙ И ИНТЕРЕСНОЙ. \r\nВ 2010 ГОДУ ВЫСТАВКА SALON DEL MOBILE ОБЕЩАЕТ БЫТЬ ЕЩЕ БОЛЕЕ РАСШИРЕННОЙ И ИНТЕРЕСНОЙ. НА ВЫСТАВКЕ SALON DEL MOBILE БУДУТ ПРЕДСТАВЛЕНЫ ВСЕ ТИПЫ МЕБЕЛИ ДЛЯ ОФИСА И ДОМА ОТ СПАЛЕН И ГОСТИНЫХ ДО VIP-КАБИНЕТОВ, ВКЛЮЧАЯ ОБОРУДОВАНИЕ ДЛЯ САДА И ДЕТСКОЙ МЕБЕЛИ. ЗАЯВКИ НА УЧАСТИЕ ПОДАЛИ БОЛЕЕ ЧЕМ 1 500 КОМПАНИЙ СО ВСЕГО МИРА. ПРЕДПОЛАГАЕТСЯ, ЧТО ЗА ВРЕМЯ ПРОВЕДЕНИЯ ВЫСТАВКИ ЕЕ ПОСЕТЯТ БОЛЕЕ 300 000 ТЫСЯЧ ЧЕЛОВЕК. ЭКСПОЗИЦИЯ ВЫСТАВКИ РАЗМЕСТИТСЯ НА ОБЩЕЙ ПЛОЩАДИ 149 871 КВ.М. В 2010 ГОДУ ЭТА ПОИСТИНЕ ГРАНДИОЗНАЯ ВЫСТАВКА БУДЕТ ПРОВОДИТЬСЯ УЖЕ В 10-Й РАЗ.\r\n'),(17,'6e9c53b4377c8bda27a391c004332b06','ПОЛУЧЕНО ПРОЧНОЕ ВОДОСТОЙКОЕ СОЕДИНЕНИЕ\r\nПОЛУЧЕНО НОВОЕ ПРОЧНОЕ ВОДОСТОЙКОЕ КЛЕЕВОЕ СОЕДИНЕНИЕ.ИЗОБРЕТЕНИЕ ОТНОСИТСЯ К ОБЛАСТИ ПОЛУЧЕНИЯ И ПРИМЕНЕНИЯ КЛЕЯЩИХ СОСТАВОВ, ИСПОЛЬЗУЕМЫХ В ДЕРЕВООБРАБАТЫВАЮЩЕЙ, МЕБЕЛЬНОЙ И СТРОИТЕЛЬНОЙ ПРОМЫШЛЕННОСТИ. ДАННАЯ КЛЕЕВАЯ КОМПОЗИЦИЯ ПРЕДНАЗНАЧЕНА ТОЛЬКО ДЛЯ ГОРЯЧЕГО ПРЕССОВАНИЯ И ИМЕЕТ В СВОЕМ СОСТАВЕ МНОГОКОМПОНЕНТНЫЙ ОТВЕРДИТЕЛЬ. \r\n\rАВТОРЫ ИЗОБРЕТЕНИЯ\r: РАЗИНЬКОВ ЕГОР МИХАЙЛОВИЧ И МЕЩЕРЯКОВА АННА АНАТОЛЬЕВНА \rПАТЕНТ РОССИЙСКОЙ ФЕДЕРАЦИИ RU2277566\rОПИСАНИЕ ИЗОБРЕТЕНИЯ\rИЗОБРЕТЕНИЕ ОТНОСИТСЯ К ОБЛАСТИ ПОЛУЧЕНИЯ И ПРИМЕНЕНИЯ КЛЕЯЩИХ СОСТАВОВ, ИСПОЛЬЗУЕМЫХ В ДЕРЕВООБРАБАТЫВАЮЩЕЙ, МЕБЕЛЬНОЙ И СТРОИТЕЛЬНОЙ ПРОМЫШЛЕННОСТИ.\rДАННАЯ КЛЕЕВАЯ КОМПОЗИЦИЯ ПРЕДНАЗНАЧЕНА ТОЛЬКО ДЛЯ ГОРЯЧЕГО ПРЕССОВАНИЯ И ИМЕЕТ В СВОЕМ СОСТАВЕ МНОГОКОМПОНЕНТНЫЙ ОТВЕРДИТЕЛЬ. ПРОТОТИПОМ КЛЕЕВОЙ КОМПОЗИЦИИ ЯВЛЯЕТСЯ КЛЕЙ, СОСТОЯЩИЙ ИЗ КАРБАМИДОФОРМАЛЬДЕГИДНОЙ СМОЛЫ, СОПОЛИМЕРА АКРИЛОНИТРИЛА С N-ВИНИЛКАПРОЛАКТАМОМ И ОТВЕРДИТЕЛЬ. В КАЧЕСТВЕ ОТВЕРДИТЕЛЯ ПРИМЕНЯЮТ ХЛОРИСТЫЙ АММОНИЙ ЛИБО АКРИЛОВУЮ КИСЛОТУ. \rИЗОБРЕТЕНИЕ РЕШАЕТ ЗАДАЧУ ПО ПОЛУЧЕНИЮ ПРОЧНОГО И ВОДОСТОЙКОГО КЛЕЕВОГО СОЕДИНЕНИЯ.\rЭТО ДОСТИГАЕТСЯ ТЕМ, ЧТО КЛЕЕВАЯ КОМПОЗИЦИЯ, ВКЛЮЧАЮЩАЯ СИНТЕТИЧЕСКУЮ СМОЛУ И ОТВЕРДИТЕЛЬ, СОГЛАСНО ИЗОБРЕТЕНИЮ, ДОПОЛНИТЕЛЬНО СОДЕРЖИТ МОДИФИКАТОР, ПРИЧЕМ В КАЧЕСТВЕ СИНТЕТИЧЕСКОЙ СМОЛЫ КЛЕЕВАЯ КОМПОЗИЦИЯ ВКЛЮЧАЕТ КАРБАМИДОМЕЛАМИНОФОРМАЛЬДЕГИДНУЮ СМОЛУ С ОТВЕРДИТЕЛЕМ 2542, В КАЧЕСТВЕ МОДИФИКАТОРА - КАРБАМИДОФОРМАЛЬДЕГИДНУЮ СМОЛУ, А В КАЧЕСТВЕ ОТВЕРДИТЕЛЯ - 10%-НЫЙ РАСТВОР ЩАВЕЛЕВОЙ КИСЛОТЫ ПРИ СЛЕДУЮЩЕМ СООТНОШЕНИИ КОМПОНЕНТОВ, МАС.Ч.:\rКАРБАМИДОМЕЛАМИНОФОРМАЛЬДЕГИДНАЯ СМОЛА\r64,5-79,2\r10%-НЫЙ РАСТВОР ЩАВЕЛЕВОЙ КИСЛОТЫ\r4,4-20,5\rОТВЕРДИТЕЛЬ ДЛЯ КАРБАМИДОМЕЛАМИНОФОРМАЛЬДЕГИДНОЙ \r0,6-2,0\rСМОЛЫ 2542\r13,0-15,8\r\n'),(48,'73b0737b640ddf58dcbdd46d5175e414','ПРОДАВЕЦ-ДИЗАЙНЕР (КУХНИ)\r\nТРЕБОВАНИЯ\rУВЕРЕННЫЙ ПОЛЬЗОВАТЕЛЬ ПК, НАВЫКИ ЧЕРЧЕНИЯ ОТ РУКИ И В ПРОГРАММАХ, ОПЫТ РАБОТЫ ДИЗАЙНЕРОМ/КОНСТРУКТОРОМ В МЕБЕЛЬНОЙ СФЕРЕ, ЭТИКА ДЕЛОВОГО ОБЩЕНИЯ\rОБЯЗАННОСТИ\rКОНСУЛЬТИРОВАНИЕ КЛИЕНТОВ ПО КУХОННОЙ МЕБЕЛИ, ОСТАВЛЕНИЕ ХУДОЖЕСТВЕННО-КОНСТРУКТОРСКИХ ПРОЕКТОВ, ПРИЕМ И ОФОРМЛЕНИЕ ЗАКАЗОВ.\rУСЛОВИЯ\rЗАРПЛАТА: 13500 ОКЛАД + % ОТ ЛИЧНЫХ ПРОДАЖ + ПРЕМИИ‚ СОВОКУПНЫЙ ДОХОД ОТ 20000 РУБ,ПОЛНЫЙ СОЦ. ПАКЕТ‚ ОФОРМЛЕНИЕ СОГЛАСНО ТК РФ\r\n'),(49,'fa5c9c5ac99f37b001a1a0421af4b144','ДИРЕКТОР МАГАЗИНА\r\nТРЕБОВАНИЯ\rВЫСШЕЕ ОБРАЗОВАНИЕ‚ ОПЫТ РУКОВОДЯЩЕЙ РАБОТЫ В РОЗНИЦЕ ОТ 3 ЛЕТ‚ ОПЫТНЫЙ ПОЛЬЗОВАТЕЛЬ ПК‚ ЭТИКА ДЕЛОВОГО ОБЩЕНИЯ‚ ЗНАНИЕ МЕТОДОВ УПРАВЛЕНИЯ И ЗАКЛЮЧЕНИЯ ДОГОВОРОВ‚ ОТЛИЧНОЕ ЗНАНИЕ ТОРГОВОГО И ТРУДОВОГО ЗАКОНОДАТЕЛЬСТВ‚ ОТВЕТСТВЕННОСТЬ‚ ИНИЦИАТИВНОСТЬ‚ АКТИВНОСТЬ.\rОБЯЗАННОСТИ\rРУКОВОДСТВО ДЕЯТЕЛЬНОСТЬЮ МАГАЗИНА‚ ОРГАНИЗАЦИЯ ЭФФЕКТИВНОЙ РАБОТЫ ПЕРСОНАЛА МАГАЗИНА‚ ФИНАНСОВО-ХОЗЯЙСТВЕННАЯ ДЕЯТЕЛЬНОСТЬ И ОТЧЕТНОСТЬ‚ ВЫПОЛНЕНИЕ ПЛАНА ПРОДАЖ‚ ОТЧЕТНОСТЬ.\rУСЛОВИЯ\rТРУДОУСТРОЙСТВО ПО ТК РФ‚ ПОЛНЫЙ СОЦ. ПАКЕТ‚ ГРАФИК РАБОТЫ 5 ЧЕРЕ 2 (168 ЧАС/МЕС)‚ ЗАРПЛАТА: ОКЛАД 28000 + % ОТ ОБОРОТА + ПРЕМИИ‚ СОВОКУПНЫЙ ДОХОД ОТ 35000 РУБ\r\n'),(50,'3187d1b1ae8eb650d8851807a7ab248b','БУХГАЛТЕР ОТДЕЛА УЧЕТА ГОТОВОЙ ПРОДУКЦИИ\r\nТРЕБОВАНИЯ\rЖЕН., 22-45, УВЕРЕННЫЙ ПОЛЬЗОВАТЕЛЬ ПК, ОПЫТ РАБОТЫ БУХГАЛТЕРОМ ПРИВЕТСВУЕТСЯ, ЗНАНИЕ БУХГАЛТЕРСКОГО УЧЕТА (БАЗОВЫЙ УРОВЕНЬ), САМОСТОЯТЕЛЬНОСТЬ, ОТВЕТСТВЕННОСТЬ, КОММУНИКАБЕЛЬНОСТЬ, БЫСТРАЯ ОБУЧАЕМОСТЬ, ЖЕЛАНИЕ РАБОТАТЬ.\rОБЯЗАННОСТИ\rРАБОТА С ПЕРВИЧНЫМИ ДОКУМЕНТАМИ ПО УЧЕТУ МПЗ ВЕДЕНИЕ ЖУРНАЛОВ-ОРДЕРОВ ПО ПРОИЗВОДСТВЕННЫМ СЧЕТАМ ФОРМИРОВАНИЕ МАТЕРИАЛЬНЫХ ОТЧЕТОВ ПОДРАЗДЕЛЕНИЙ ИСПОЛНЕНИЕ ДОПОЛНИТЕЛЬНЫХ ФУНКЦИЙ ПО УКАЗАНИЮ РУКОВОДИТЕЛЯ\rУСЛОВИЯ\rГРАФИК РАБОТЫ 5 ДНЕЙ В НЕДЕЛЮ, АДРЕС РАБОТЫ Г. ШАТУРА, БОТИНСКИЙ ПР-Д, 37. ЗАРПЛАТА: ОКЛАД 10 800 Р. + ПРЕМИЯ 40% ОТ ОКЛАДА, ПОЛНЫЙ СОЦ. ПАКЕТ.\r\n'),(59,'e3cf494db938598c75296bfacd6efe72','ТЕСТ МАСЛО ГИДРАВЛИЧЕСКОЕ ВИПРО\r\nТЕСТ МАСЛО ГИДРАВЛИЧЕСКОЕ ВИПРО\r\nМАСЛО ПРЕДНАЗНАЧЕНО ДЛЯ СИСТЕМ ГИДРОУСИЛИТЕЛЯ РУЛЯ, ГИДРООБЪЕМНЫХ ПЕРЕДАЧ И ГИДРАВЛИЧЕСКИХ СИСТЕМ АВТОМОБИЛЬНОЙ ТЕХНИКИ, В ТОМ ЧИСЛЕ ТЕХНИКИ СПЕЦИАЛЬНОГО НАЗНАЧЕНИЯ.\r\n'),(60,'ae9dda3b2b09a375fe30c34c3b313573','КИНЕМАТИЧЕСКАЯ ВЯЗКОСТЬ ПРИ 100°C ПО ГОСТ 33\r\nКИНЕМАТИЧЕСКАЯ ВЯЗКОСТЬ ПРИ 100°C ПО ГОСТ 33\r\nКОМПАНИЯ СИМЭКС-ХИМ РАСПОЛАГАЕТ АТТЕСТОВАННОЙ ЛАБОРАТОРИЕЙ АНАЛИЗА СМАЗОЧНЫХ МАТЕРИАЛОВ, КОТОРАЯ ОСНАЩЕНА СОВРЕМЕННЫМ ОБОРУДОВАНИЕМ. СПЕЦИАЛИСТЫ КОМПАНИИ, ОБЛАДАЯ НАКОПЛЕННЫМ НАУЧНЫМ ОПЫТОМ И ЗНАНИЯМИ В РАЗРАБОТКЕ, ПРОВЕРКЕ И ПРОИЗВОДСТВЕ СМАЗОЧНЫХ МАТЕРИАЛОВ, ОБЕСПЕЧИВАЮТ ПОСТОЯННЫЙ КОНТРОЛЬ КАЧЕСТВА СЫРЬЕВЫХ КОМПОНЕНТОВ И ПРОДУКЦИИ, АДАПТАЦИЮ ПРОДУКТОВ К СПЕЦИФИЧЕСКИМ ТРЕБОВАНИЯМ ЗАКАЗЧИКОВ, РЕАЛИЗУЮЩИХ СВОИ ПРОЕКТЫ В РАЗНЫХ СТРАНАХ, ГЕОГРАФИЧЕСКИХ ПОЯСАХ И ПОГОДНЫХ УСЛОВИЯХ.\nНАША ИСПЫТАТЕЛЬНАЯ ЛАБОРАТОРИЯ АНАЛИЗА СМАЗОЧНЫХ МАТЕРИАЛОВ ПРЕДЛАГАЕТ УСЛУГИ ПО ПРОВЕДЕНИЮ АНАЛИЗА ОПРЕДЕЛЕНИЯ ТЕРМООКИСЛИТЕЛЬНОЙ СТАБИЛЬНОСТИ И КОРРОЗИОННОЙ АКТИВНОСТИ СМАЗОЧНЫХ МАТЕРИАЛОВ. ДАННЫЙ АНАЛИЗ ПРОВОДИТСЯ СОГЛАСНО ГОСТ 20944-75.\n\nМЕТОДИКА ПРОВЕДЕНИЯ АНАЛИЗА НА ОПРЕДЕЛЕНИЕ ТЕРМООКИСЛИТЕЛЬНОЙ СТАБИЛЬНОСТИ И КОРРОЗИОННОЙ АКТИВНОСТИ ПО ГОСТ 20944-75\n\nСУЩНОСТЬ МЕТОДА ЗАКЛЮЧАЕТСЯ В ОКИСЛЕНИИ ЖИДКОСТИ В КОНТАКТЕ С МЕТАЛЛАМИ И ВОЗДУХОМ, С НАГРЕВОМ ДО 200°C. ТЕРМООКИСЛИТЕЛЬНУЮ СТАБИЛЬНОСТЬ ЖИДКОСТИ ОЦЕНИВАЮТ ПО ИЗМЕНЕНИЮ ВНЕШНЕГО ВИ\r\n'),(61,'650624d94f06153fa626cb4dc8908db5','КИНЕМАТИЧЕСКАЯ ВЯЗКОСТЬ ПРИ 40°C ПО ГОСТ 33\r\nКИНЕМАТИЧЕСКАЯ ВЯЗКОСТЬ ПРИ 40°C ПО ГОСТ 33\r\nКОМПАНИЯ СИМЭКС-ХИМ РАСПОЛАГАЕТ АТТЕСТОВАННОЙ ЛАБОРАТОРИЕЙ АНАЛИЗА СМАЗОЧНЫХ МАТЕРИАЛОВ, КОТОРАЯ ОСНАЩЕНА СОВРЕМЕННЫМ ОБОРУДОВАНИЕМ. СПЕЦИАЛИСТЫ КОМПАНИИ, ОБЛАДАЯ НАКОПЛЕННЫМ НАУЧНЫМ ОПЫТОМ И ЗНАНИЯМИ В РАЗРАБОТКЕ, ПРОВЕРКЕ И ПРОИЗВОДСТВЕ СМАЗОЧНЫХ МАТЕРИАЛОВ, ОБЕСПЕЧИВАЮТ ПОСТОЯННЫЙ КОНТРОЛЬ КАЧЕСТВА СЫРЬЕВЫХ КОМПОНЕНТОВ И ПРОДУКЦИИ, АДАПТАЦИЮ ПРОДУКТОВ К СПЕЦИФИЧЕСКИМ ТРЕБОВАНИЯМ ЗАКАЗЧИКОВ, РЕАЛИЗУЮЩИХ СВОИ ПРОЕКТЫ В РАЗНЫХ СТРАНАХ, ГЕОГРАФИЧЕСКИХ ПОЯСАХ И ПОГОДНЫХ УСЛОВИЯХ.\nНАША ИСПЫТАТЕЛЬНАЯ ЛАБОРАТОРИЯ АНАЛИЗА СМАЗОЧНЫХ МАТЕРИАЛОВ ПРЕДЛАГАЕТ УСЛУГИ ПО ПРОВЕДЕНИЮ АНАЛИЗА ОПРЕДЕЛЕНИЯ ТЕРМООКИСЛИТЕЛЬНОЙ СТАБИЛЬНОСТИ И КОРРОЗИОННОЙ АКТИВНОСТИ СМАЗОЧНЫХ МАТЕРИАЛОВ. ДАННЫЙ АНАЛИЗ ПРОВОДИТСЯ СОГЛАСНО ГОСТ 20944-75.\n\nМЕТОДИКА ПРОВЕДЕНИЯ АНАЛИЗА НА ОПРЕДЕЛЕНИЕ ТЕРМООКИСЛИТЕЛЬНОЙ СТАБИЛЬНОСТИ И КОРРОЗИОННОЙ АКТИВНОСТИ ПО ГОСТ 20944-75\n\nСУЩНОСТЬ МЕТОДА ЗАКЛЮЧАЕТСЯ В ОКИСЛЕНИИ ЖИДКОСТИ В КОНТАКТЕ С МЕТАЛЛАМИ И ВОЗДУХОМ, С НАГРЕВОМ ДО 200°C. ТЕРМООКИСЛИТЕЛЬНУЮ СТАБИЛЬНОСТЬ ЖИДКОСТИ ОЦЕНИВАЮТ ПО ИЗМЕНЕНИЮ ВНЕШНЕГО ВИ\r\n'),(62,'e625b09d14ad10f2e63b21d8931fdaae','ТЕСТ МАСЛО ГИДРАВЛИЧЕСКОЕ SIMY HVLP-32 БОЧКА 170КГ\r\nМАСЛО ГИДРАВЛИЧЕСКОЕ SIMY HVLP-32 БОЧКА 170КГ\r\nВЫСОКОЭФФЕКТИВНОЕ ГИДРАВЛИЧЕСКОЕ МАСЛО, РАЗРАБОТАННОЕ ДЛЯ НАИБОЛЕЕ ПОЛНОГО СООТВЕТСТВИЯ СПЕЦИФИЧЕСКИМ ТРЕБОВАНИЯМ ЭКСПЛУАТАЦИИ В РОССИЙСКИХ УСЛОВИЯХ СОВРЕМЕННЫХ ГИДРАВЛИЧЕСКИХ СИСТЕМ, ПРИМЕНЯЮЩИХСЯ В ПРОМЫШЛЕННОМ ОБОРУДОВАНИИ И МОБИЛЬНОЙ ТЕХНИКЕ.\nОТВЕЧАЕТ ТРЕБОВАНИЯМ EATON VICKERS, BOSCH REXROTH И НЕМЕЦКОМУ СТАНДАРТУ DIN51524-3. \nХОРОШИЕ ПОКАЗАТЕЛИ ГИДРОЛИТИЧЕСКОЙ СТАБИЛЬНОСТИ И ВОДООТТАЛКИВАЮЩИЕ СВОЙСТВА СПОСОБСТВУЮТ ПРЕВОСХОДНОЙ ФИЛЬТРУЕМОСТИ ПРИ ПОПАДАНИИ ВОДЫ. АНТИПЕННЫЕ ПРИСАДКИ ОБЕСПЕЧИВАЮТ НИЗКИЙ УРОВЕНЬ ПЕНООБРАЗОВАНИЯ, БЫСТРЫЙ ОТВОД ВОЗДУХА, БЕСПЕРЕБОЙНУЮ И ЭФФЕКТИВНУЮ РАБОТУ ТЕХНИКИ.\nБЛАГОДАРЯ УЛУЧШЕННЫМ ВЯЗКОСТНО-ТЕМПЕРАТУРНЫМ ХАРКТЕРИСТИКАМ, МАСЛО СОХРАНЯЕТ ПРЕВОСХОДНУЮ ТЕКУЧЕСТЬ И ПРОКАЧИВАЕМОСТЬ ПРИ ОТРИЦАТЕЛЬНЫХ ТЕМПЕРАТУРАХ, ЧТО ПОЗВОЛЯЕТ ОБЕСПЕЧИТЬ ЛЕГКИЙ ПУСК ГИДРОПРИВОДА.\r\n'),(63,'c7d727c2588de0e1a8c80d043394008d','ТЕСТ МАСЛО ГИДРАВЛИЧЕСКОЕ ВИПРО\r\nТЕСТ МАСЛО ГИДРАВЛИЧЕСКОЕ ВИПРО\r\nМАСЛО РАЗРАБОТАНО В НАУЧНОМ ЦЕНТРЕ СИМЭКС-ХИМ ПО ТЕХНИЧЕСКОМУ ЗАДАНИЮ РОССИЙСКИХ ПРОИЗВОДИТЕЛЕЙ АВТОМОБИЛЬНОЙ ТЕХНИКИ КАК АНАЛОГ ГИДРАВЛИЧЕСКИХ ЖИДКОСТЕЙ СЕГМЕНТА CHF/PSF ПРЕМИАЛЬНОГО КАЧЕСТВА ОТ ВЕДУЩИХ МИРОВЫХ ПРОИЗВОДИТЕЛЕЙ СМАЗОЧНЫХ МАТЕРИАЛОВ. ТЕХНОЛОГИЕЙ ИЗГОТОВЛЕНИЯ МАСЛА ВИПРО ПРЕДУСМОТРЕНО ПРИМЕНЕНИЕ УНИКАЛЬНЫХ ПРИСАДОК И СПЕЦИАЛЬНО ПОДОБРАННЫХ СИНТЕТИЧЕСКИХ БАЗОВЫХ МАСЕЛ — ПОЛИАЛЬФАОЛЕФИНОВ (ПАО), ОБЕСПЕЧИВАЮЩИХ ОПТИМАЛЬНУЮ РАБОТУ И ЗАЩИТУ ГИДРАВЛИЧЕСКИХ СИСТЕМ. ГИДРАВЛИЧЕСКОЕ СИНТЕТИЧЕСКОЕ МАСЛО ВИПРО ПРОИЗВОДИТСЯ В СТРОГОМ СООТВЕТСТВИИ С:\r\n\r\nМАСЛО ВИПРО СОЗДАНО ДЛЯ ЛЮБЫХ, В ТОМ ЧИСЛЕ ЭКСТРЕМАЛЬНЫХ, УСЛОВИЙ ЭКСПЛУАТАЦИИ И ИМЕЕТ СЛЕДУЮЩИЕ ПРЕИМУЩЕСТВА:\r\nМАСЛО ПЕРВОЙ ЗАЛИВКИ НА КОНВЕЙЕРЕ;\r\nПОДХОДИТ ДЛЯ ЛЕГКОВЫХ И ГРУЗОВЫХ АВТОМОБИЛЕЙ ТАКИХ МАРОК КАК: КАМАЗ, ГАЗ, МАЗ, УРАЛ, MAN, MERCEDES, VOLVO, SCANIA;\r\nПОЛНОСТЬЮ СИНТЕТИЧЕСКОЕ;\r\nРАБОТОСПОСОБНО ОТ МИНУС 50°C ДО 140°C;\r\nТЕМПЕРАТУРА ЗАСТЫВАНИЯ НИЖЕ МИНУС 60°C;\r\nИНДЕКС ВЯЗКОСТИ 315;\r\nОТЛИЧНАЯ ПРОКАЧИВАЕМОСТЬ В СИСТЕМЕ, ДАЖЕ ПРИ НИЗКИХ ТЕМПЕРАТУРАХ;\r\nМАСЛО НЕ ОКАЗЫ\r\n'),(64,'e625b09d14ad10f2e63b21d8931fdaae','ТЕСТ МАСЛО ГИДРАВЛИЧЕСКОЕ SIMY HVLP-32 БОЧКА 170КГ\r\nМАСЛО ГИДРАВЛИЧЕСКОЕ SIMY HVLP-32 БОЧКА 170КГ\r\nВЫСОКОЭФФЕКТИВНОЕ ГИДРАВЛИЧЕСКОЕ МАСЛО, РАЗРАБОТАННОЕ ДЛЯ НАИБОЛЕЕ ПОЛНОГО СООТВЕТСТВИЯ СПЕЦИФИЧЕСКИМ ТРЕБОВАНИЯМ ЭКСПЛУАТАЦИИ В РОССИЙСКИХ УСЛОВИЯХ СОВРЕМЕННЫХ ГИДРАВЛИЧЕСКИХ СИСТЕМ, ПРИМЕНЯЮЩИХСЯ В ПРОМЫШЛЕННОМ ОБОРУДОВАНИИ И МОБИЛЬНОЙ ТЕХНИКЕ.\nОТВЕЧАЕТ ТРЕБОВАНИЯМ EATON VICKERS, BOSCH REXROTH И НЕМЕЦКОМУ СТАНДАРТУ DIN51524-3. \nХОРОШИЕ ПОКАЗАТЕЛИ ГИДРОЛИТИЧЕСКОЙ СТАБИЛЬНОСТИ И ВОДООТТАЛКИВАЮЩИЕ СВОЙСТВА СПОСОБСТВУЮТ ПРЕВОСХОДНОЙ ФИЛЬТРУЕМОСТИ ПРИ ПОПАДАНИИ ВОДЫ. АНТИПЕННЫЕ ПРИСАДКИ ОБЕСПЕЧИВАЮТ НИЗКИЙ УРОВЕНЬ ПЕНООБРАЗОВАНИЯ, БЫСТРЫЙ ОТВОД ВОЗДУХА, БЕСПЕРЕБОЙНУЮ И ЭФФЕКТИВНУЮ РАБОТУ ТЕХНИКИ.\nБЛАГОДАРЯ УЛУЧШЕННЫМ ВЯЗКОСТНО-ТЕМПЕРАТУРНЫМ ХАРКТЕРИСТИКАМ, МАСЛО СОХРАНЯЕТ ПРЕВОСХОДНУЮ ТЕКУЧЕСТЬ И ПРОКАЧИВАЕМОСТЬ ПРИ ОТРИЦАТЕЛЬНЫХ ТЕМПЕРАТУРАХ, ЧТО ПОЗВОЛЯЕТ ОБЕСПЕЧИТЬ ЛЕГКИЙ ПУСК ГИДРОПРИВОДА.\r\n'),(65,'a798b63cfaedf79a286b633809b21038','ТЕСТ МАСЛО ГИДРАВЛИЧЕСКОЕ SI-HYDRO ВМГЗ-45\r\nМАСЛО ГИДРАВЛИЧЕСКОЕ SI-HYDRO ВМГЗ-45\r\nПРИМЕНЯЕТСЯ В КАЧЕСТВЕ ВСЕСЕЗОННОЙ РАБОЧЕЙ ЖИДКОСТИ ДЛЯ СИСТЕМ ГИДРОПРИВОДА СТРОИТЕЛЬНЫХ, ДОРОЖНЫХ, ЛЕСОЗАГОТОВИТЕЛЬНЫХ, ПОДЪЕМНО-ТРАНСПОРТНЫХ, СЕЛЬСКОХОЗЯЙСТВЕННЫХ И ДРУГИХ МАШИН, РАБОТАЮЩИХ НА ОТКРЫТОМ ВОЗДУХЕ ПРИ ТЕМПЕРАТУРАХ В РАБОЧЕМ ОБЪЕМЕ МАСЛА ОТ МИНУС 30 ДО ПЛЮС 80℃ В ЗАВИСИМОСТИ ОТ ТИПА ГИДРОНАСОСА.\r\n'),(66,'745a0217196509a87035261c7325ab8b','ADMIN-SIMEX\r\n\r\n'),(67,'c35b7849703d09bca119941e097e2049','ТЕСТ МАСЛО ГИДРАВЛИЧЕСКОЕ SI-HYDRO ВМГЗ-45 КАНИСТРА 17КГ\r\nМАСЛО ГИДРАВЛИЧЕСКОЕ SI-HYDRO ВМГЗ-45 КАНИСТРА 17КГ\r\nПРИМЕНЯЕТСЯ В КАЧЕСТВЕ ВСЕСЕЗОННОЙ РАБОЧЕЙ ЖИДКОСТИ ДЛЯ СИСТЕМ ГИДРОПРИВОДА СТРОИТЕЛЬНЫХ, ДОРОЖНЫХ, ЛЕСОЗАГОТОВИТЕЛЬНЫХ, ПОДЪЕМНО-ТРАНСПОРТНЫХ, СЕЛЬСКОХОЗЯЙСТВЕННЫХ И ДРУГИХ МАШИН, РАБОТАЮЩИХ НА ОТКРЫТОМ ВОЗДУХЕ ПРИ ТЕМПЕРАТУРАХ В РАБОЧЕМ ОБЪЕМЕ МАСЛА ОТ МИНУС 30 ДО ПЛЮС 80℃ В ЗАВИСИМОСТИ ОТ ТИПА ГИДРОНАСОСА.\r\n'),(68,'9b3eb51e1bca5e992800426b36bc2587','ТЕСТ МАСЛО ГИДРАВЛИЧЕСКОЕ SIMY HVLP-32 КАНИСТРА 17КГ\r\nМАСЛО ГИДРАВЛИЧЕСКОЕ SIMY HVLP-32 КАНИСТРА 17КГ\r\nВЫСОКОЭФФЕКТИВНОЕ ГИДРАВЛИЧЕСКОЕ МАСЛО, РАЗРАБОТАННОЕ ДЛЯ НАИБОЛЕЕ ПОЛНОГО СООТВЕТСТВИЯ СПЕЦИФИЧЕСКИМ ТРЕБОВАНИЯМ ЭКСПЛУАТАЦИИ В РОССИЙСКИХ УСЛОВИЯХ СОВРЕМЕННЫХ ГИДРАВЛИЧЕСКИХ СИСТЕМ, ПРИМЕНЯЮЩИХСЯ В ПРОМЫШЛЕННОМ ОБОРУДОВАНИИ И МОБИЛЬНОЙ ТЕХНИКЕ.\nОТВЕЧАЕТ ТРЕБОВАНИЯМ EATON VICKERS, BOSCH REXROTH И НЕМЕЦКОМУ СТАНДАРТУ DIN51524-3. \nХОРОШИЕ ПОКАЗАТЕЛИ ГИДРОЛИТИЧЕСКОЙ СТАБИЛЬНОСТИ И ВОДООТТАЛКИВАЮЩИЕ СВОЙСТВА СПОСОБСТВУЮТ ПРЕВОСХОДНОЙ ФИЛЬТРУЕМОСТИ ПРИ ПОПАДАНИИ ВОДЫ. АНТИПЕННЫЕ ПРИСАДКИ ОБЕСПЕЧИВАЮТ НИЗКИЙ УРОВЕНЬ ПЕНООБРАЗОВАНИЯ, БЫСТРЫЙ ОТВОД ВОЗДУХА, БЕСПЕРЕБОЙНУЮ И ЭФФЕКТИВНУЮ РАБОТУ ТЕХНИКИ.\nБЛАГОДАРЯ УЛУЧШЕННЫМ ВЯЗКОСТНО-ТЕМПЕРАТУРНЫМ ХАРКТЕРИСТИКАМ, МАСЛО СОХРАНЯЕТ ПРЕВОСХОДНУЮ ТЕКУЧЕСТЬ И ПРОКАЧИВАЕМОСТЬ ПРИ ОТРИЦАТЕЛЬНЫХ ТЕМПЕРАТУРАХ, ЧТО ПОЗВОЛЯЕТ ОБЕСПЕЧИТЬ ЛЕГКИЙ ПУСК ГИДРОПРИВОДА.\r\n'),(69,'3ebdc1d7bb02eeb8d678c45ed8163cd3','ТЕСТ МАСЛО ГИДРАВЛИЧЕСКОЕ SI-HYDRO ВМГЗ-45 БОЧКА 170КГ\r\nМАСЛО ГИДРАВЛИЧЕСКОЕ SI-HYDRO ВМГЗ-45 БОЧКА 170КГ\r\nПРИМЕНЯЕТСЯ В КАЧЕСТВЕ ВСЕСЕЗОННОЙ РАБОЧЕЙ ЖИДКОСТИ ДЛЯ СИСТЕМ ГИДРОПРИВОДА СТРОИТЕЛЬНЫХ, ДОРОЖНЫХ, ЛЕСОЗАГОТОВИТЕЛЬНЫХ, ПОДЪЕМНО-ТРАНСПОРТНЫХ, СЕЛЬСКОХОЗЯЙСТВЕННЫХ И ДРУГИХ МАШИН, РАБОТАЮЩИХ НА ОТКРЫТОМ ВОЗДУХЕ ПРИ ТЕМПЕРАТУРАХ В РАБОЧЕМ ОБЪЕМЕ МАСЛА ОТ МИНУС 30 ДО ПЛЮС 80℃ В ЗАВИСИМОСТИ ОТ ТИПА ГИДРОНАСОСА.\r\n'),(70,'e625b09d14ad10f2e63b21d8931fdaae','ТЕСТ МАСЛО ГИДРАВЛИЧЕСКОЕ SIMY HVLP-32 БОЧКА 170КГ\r\nМАСЛО ГИДРАВЛИЧЕСКОЕ SIMY HVLP-32 БОЧКА 170КГ\r\nВЫСОКОЭФФЕКТИВНОЕ ГИДРАВЛИЧЕСКОЕ МАСЛО, РАЗРАБОТАННОЕ ДЛЯ НАИБОЛЕЕ ПОЛНОГО СООТВЕТСТВИЯ СПЕЦИФИЧЕСКИМ ТРЕБОВАНИЯМ ЭКСПЛУАТАЦИИ В РОССИЙСКИХ УСЛОВИЯХ СОВРЕМЕННЫХ ГИДРАВЛИЧЕСКИХ СИСТЕМ, ПРИМЕНЯЮЩИХСЯ В ПРОМЫШЛЕННОМ ОБОРУДОВАНИИ И МОБИЛЬНОЙ ТЕХНИКЕ.\nОТВЕЧАЕТ ТРЕБОВАНИЯМ EATON VICKERS, BOSCH REXROTH И НЕМЕЦКОМУ СТАНДАРТУ DIN51524-3. \nХОРОШИЕ ПОКАЗАТЕЛИ ГИДРОЛИТИЧЕСКОЙ СТАБИЛЬНОСТИ И ВОДООТТАЛКИВАЮЩИЕ СВОЙСТВА СПОСОБСТВУЮТ ПРЕВОСХОДНОЙ ФИЛЬТРУЕМОСТИ ПРИ ПОПАДАНИИ ВОДЫ. АНТИПЕННЫЕ ПРИСАДКИ ОБЕСПЕЧИВАЮТ НИЗКИЙ УРОВЕНЬ ПЕНООБРАЗОВАНИЯ, БЫСТРЫЙ ОТВОД ВОЗДУХА, БЕСПЕРЕБОЙНУЮ И ЭФФЕКТИВНУЮ РАБОТУ ТЕХНИКИ.\nБЛАГОДАРЯ УЛУЧШЕННЫМ ВЯЗКОСТНО-ТЕМПЕРАТУРНЫМ ХАРКТЕРИСТИКАМ, МАСЛО СОХРАНЯЕТ ПРЕВОСХОДНУЮ ТЕКУЧЕСТЬ И ПРОКАЧИВАЕМОСТЬ ПРИ ОТРИЦАТЕЛЬНЫХ ТЕМПЕРАТУРАХ, ЧТО ПОЗВОЛЯЕТ ОБЕСПЕЧИТЬ ЛЕГКИЙ ПУСК ГИДРОПРИВОДА.\r\n'),(71,'9dc81310e5f6940cd74425623ed50b52','МЕБЕЛЬНАЯ КОМПАНИЯ\r\nНАША КОМПАНИЯ СУЩЕСТВУЕТ НА РОССИЙСКОМ РЫНКЕ С 1992 ГОДА. ЗА ЭТО ВРЕМЯ «МЕБЕЛЬНАЯ КОМПАНИЯ» ПРОШЛА БОЛЬШОЙ ПУТЬ ОТ МАЛЕНЬКОЙ ТОРГОВОЙ ФИРМЫ ДО ОДНОГО ИЗ КРУПНЕЙШИХ ПРОИЗВОДИТЕЛЕЙ КОРПУСНОЙ МЕБЕЛИ В РОССИИ.\n«МЕБЕЛЬНАЯ КОМПАНИЯ» ОСУЩЕСТВЛЯЕТ ПРОИЗВОДСТВО МЕБЕЛИ НА ВЫСОКОКЛАССНОМ ОБОРУДОВАНИИ С ПРИМЕНЕНИЕМ МИНИМАЛЬНОЙ ДОЛИ РУЧНОГО ТРУДА, ЧТО ПОЗВОЛЯЕТ ОБЕСПЕЧИТЬ ВЫСОКОЕ КАЧЕСТВО НАШЕЙ ПРОДУКЦИИ. НАЛАЖЕН ПРОИЗВОДСТВЕННЫЙ ПРОЦЕСС КАК МАССОВОГО И ИНДИВИДУАЛЬНОГО ХАРАКТЕРА, ЧТО С ОДНОЙ СТОРОНЫ ПОЗВОЛЯЕТ ОБЕСПЕЧИТЬ ПОСТОЯННУЮ НОМЕНКЛАТУРУ ИЗДЕЛИЙ И ИНДИВИДУАЛЬНЫЙ ПОДХОД – С ДРУГОЙ.\nНАША ПРОДУКЦИЯ\rНАШИ УСЛУГИ\r\n'),(72,'620df7caf8a17c8bf12a0034e654b636','КАТАЛОГ\r\nTEXT HERE....\r\n'),(73,'80bb21a1864134289efc6aa40660e4c2','О КОМПАНИИ\r\nTEXT HERE....\r\n'),(74,'f26628b010c97b065e503dd8b8400b1c','БРЕНДЫ\r\nTEXT HERE....\r\n'),(75,'2f377909fbad08ee2515c7abe8424055','ЛАБОРАТОРИЯ\r\nTEXT HERE....\r\n'),(76,'71dd1d3953a85b5bf2e8195e1cf6a692','КУПИТЬ\r\nTEXT HERE....\r\n'),(77,'e43c302059fe919ae3b83d1efefa572f','ПРОИЗВОДСТВО СПЕЦИАЛИЗИРОВАННЫХ СМАЗОЧНЫХ МАТЕРИАЛОВ\r\n\r\n'),(78,'387d888