 присадки обеспечивают низкий уровень пенообразования, быстрый отвод воздуха, бесперебойную и эффективную работу техники.\nБлагодаря улучшенным вязкостно-температурным харктеристикам, масло сохраняет превосходную текучесть и прокачиваемость при отрицательных температурах, что позволяет обеспечить легкий пуск гидропривода.',NULL),(265,254,525,526,4,'Картинка','import_files/c7/DSC004677.jpg',NULL),(266,254,527,528,4,'Картинка','import_files/c7/Бочка-SI3.jpg',NULL),(267,254,529,534,4,'Изготовитель',NULL,NULL),(268,267,530,531,5,'Ид','06a8d23a-eebd-11ef-957b-b53a4301cb44',NULL),(269,267,532,533,5,'Наименование','Симекс-Хим ООО',NULL),(270,254,535,620,4,'ЗначенияСвойств',NULL,NULL),(271,270,536,541,5,'ЗначенияСвойства',NULL,NULL),(272,271,537,538,6,'Ид','4a529bcd-9847-11f0-9593-f61e6c17d77a',NULL),(273,271,539,540,6,'Значение','4a529bce-9847-11f0-9593-f61e6c17d77a',NULL),(274,270,542,547,5,'ЗначенияСвойства',NULL,NULL),(275,274,543,544,6,'Ид','4b9ff4e8-9847-11f0-9593-f61e6c17d77a',NULL),(276,274,545,546,6,'Значение','масло базовое с присадками',NULL),(277,270,548,553,5,'ЗначенияСвойства',NULL,NULL),(278,277,549,550,6,'Ид','4a529bd3-9847-11f0-9593-f61e6c17d77a',NULL),(279,277,551,552,6,'Значение','4a529bec-9847-11f0-9593-f61e6c17d77a',NULL),(280,270,554,559,5,'ЗначенияСвойства',NULL,NULL),(281,280,555,556,6,'Ид','4b9ff4db-9847-11f0-9593-f61e6c17d77a',NULL),(282,280,557,558,6,'Значение','04958734-046-2020',NULL),(283,270,560,565,5,'ЗначенияСвойства',NULL,NULL),(284,283,561,562,6,'Ид','4b9ff40b-9847-11f0-9593-f61e6c17d77a',NULL),(285,283,563,564,6,'Значение','17',NULL),(286,270,566,571,5,'ЗначенияСвойства',NULL,NULL),(287,286,567,568,6,'Ид','4b9ff40c-9847-11f0-9593-f61e6c17d77a',NULL),(288,286,569,570,6,'Значение','4b9ff40e-9847-11f0-9593-f61e6c17d77a',NULL),(289,270,572,577,5,'ЗначенияСвойства',NULL,NULL),(290,289,573,574,6,'Ид','4b9ff415-9847-11f0-9593-f61e6c17d77a',NULL),(291,289,575,576,6,'Значение','cb364f73-9ab0-11f0-9593-f61e6c17d77a',NULL),(292,270,578,583,5,'Значен