6',NULL),(585,583,1163,1164,6,'Коэффициент','1',NULL),(586,578,1167,1170,4,'Группы',NULL,NULL),(587,586,1168,1169,5,'Ид','5c52b49f-f11b-11f0-959b-ce787b58ee6d',NULL),(588,578,1171,1172,4,'Описание','Масло разработано в научном центре СИМЭКС-ХИМ по техническому заданию российских производителей автомобильной техники как аналог гидравлических жидкостей сегмента CHF/PSF премиального качества от ведущих мировых производителей смазочных материалов. Технологией изготовления масла ВИПРО предусмотрено применение уникальных присадок и специально подобранных синтетических базовых масел — полиальфаолефинов (ПАО), обеспечивающих оптимальную работу и защиту гидравлических систем. Гидравлическое синтетическое масло ВИПРО производится в строгом соответствии с:\n\nМасло ВИПРО создано для любых, в том числе экстремальных, условий эксплуатации и имеет следующие преимущества:\nмасло первой заливки на конвейере;\nподходит для легковых и грузовых автомобилей таких марок как: КАМАЗ, ГАЗ, МАЗ, Урал, MAN, Mercedes, Volvo, Scania;\nполностью синтетическое;\nработоспособно от минус 50°C до 140°C;\nтемпература застывания ниже минус 60°C;\nиндекс вязкости 315;\nотличная прокачиваемость в системе, даже при низких температурах;\nмасло не оказы',NULL),(589,578,1173,1174,4,'Картинка','import_files/56/6.jpg',NULL),(590,578,1175,1176,4,'Картинка','import_files/56/1.jpg',NULL),(591,578,1177,1178,4,'Картинка','import_files/56/1.jpg',NULL),(592,578,1179,1180,4,'Картинка','import_files/56/2.jpg',NULL),(593,578,1181,1182,4,'Картинка','import_files/56/3.jpg',NULL),(594,578,1183,1184,4,'Картинка','import_files/56/4.jpg',NULL),(595,578,1185,1186,4,'Картинка','import_files/56/5.jpg',NULL),(596,578,1187,1188,4,'Картинка','import_files/56/7.jpg',NULL),(597,578,1189,1190,4,'Картинка','import_files/56/8.jpg',NULL),(598,578,1191,1192,4,'Картинка','import_files/56/9.jpg',NULL),(599,578,1193,1194,4,'Картинка','import_files/56/VIPRO-OIL-TDS.pdf',NULL),(600,578,1195,1200,4,'Изготовитель',NULL,NULL),(601,600,1196,1197