енным вязкостно-температурным харктеристикам, масло сохраняет превосходную текучесть и прокачиваемость при отрицательных температурах, что позволяет обеспечить легкий пуск гидропривода.',NULL),(689,678,1373,1374,4,'Картинка','import_files/f3/Бочка-SI3.jpg',NULL),(690,678,1375,1380,4,'Изготовитель',NULL,NULL),(691,690,1376,1377,5,'Ид','06a8d23a-eebd-11ef-957b-b53a4301cb44',NULL),(692,690,1378,1379,5,'Наименование','Симекс-Хим ООО',NULL),(693,678,1381,1466,4,'ЗначенияСвойств',NULL,NULL),(694,693,1382,1387,5,'ЗначенияСвойства',NULL,NULL),(695,694,1383,1384,6,'Ид','4a529bcd-9847-11f0-9593-f61e6c17d77a',NULL),(696,694,1385,1386,6,'Значение','4a529bce-9847-11f0-9593-f61e6c17d77a',NULL),(697,693,1388,1393,5,'ЗначенияСвойства',NULL,NULL),(698,697,1389,1390,6,'Ид','4b9ff4e8-9847-11f0-9593-f61e6c17d77a',NULL),(699,697,1391,1392,6,'Значение','масло базовое с присадками',NULL),(700,693,1394,1399,5,'ЗначенияСвойства',NULL,NULL),(701,700,1395,1396,6,'Ид','4a529bd3-9847-11f0-9593-f61e6c17d77a',NULL),(702,700,1397,1398,6,'Значение','4a529bec-9847-11f0-9593-f61e6c17d77a',NULL),(703,693,1400,1405,5,'ЗначенияСвойства',NULL,NULL),(704,703,1401,1402,6,'Ид','4b9ff4db-9847-11f0-9593-f61e6c17d77a',NULL),(705,703,1403,1404,6,'Значение','04958734-046-2020',NULL),(706,693,1406,1411,5,'ЗначенияСвойства',NULL,NULL),(707,706,1407,1408,6,'Ид','4b9ff40b-9847-11f0-9593-f61e6c17d77a',NULL),(708,706,1409,1410,6,'Значение','170',NULL),(709,693,1412,1417,5,'ЗначенияСвойства',NULL,NULL),(710,709,1413,1414,6,'Ид','4b9ff40c-9847-11f0-9593-f61e6c17d77a',NULL),(711,709,1415,1416,6,'Значение','4b9ff40e-9847-11f0-9593-f61e6c17d77a',NULL),(712,693,1418,1423,5,'ЗначенияСвойства',NULL,NULL),(713,712,1419,1420,6,'Ид','4b9ff415-9847-11f0-9593-f61e6c17d77a',NULL),(714,712,1421,1422,6,'Значение','cb364f73-9ab0-11f0-9593-f61e6c17d77a',NULL),(715,693,1424,1429,5,'ЗначенияСвойства',NULL,NULL),(716,715,1425,1426,6,'Ид','4b9ff41d-9847-11f0-9593-f61e6c17d77a',NULL),(717,715,1427,1428,6,'Значение','3bf53e17-9a97-11f0-9593-